static int contains_literal(const char *haystack, const char *needle) {
  if (!haystack || !needle || !needle[0]) {
    return 0;
  }
  for (const char *cursor = haystack; *cursor; ++cursor) {
    const char *h = cursor;
    const char *n = needle;
    while (*h && *n && *h == *n) {
      ++h;
      ++n;
    }
    if (!*n) {
      return 1;
    }
  }
  return 0;
}

static const char *process_event_function_provenance(const char *function_path, const char *runtime_function_path) {
  if (contains_literal(function_path, "SelfTest") ||
      contains_literal(function_path, ".LiveProcessEvent") ||
      contains_literal(runtime_function_path, "SelfTest") ||
      contains_literal(runtime_function_path, ".LiveProcessEvent")) {
    return "self-test";
  }
  return "runtime";
}

static int process_event_function_native_identity(
  const char *function_path,
  const char *runtime_function_path,
  size_t param_count
) {
  const char *provenance = process_event_function_provenance(function_path, runtime_function_path);
  return function_path && function_path[0] &&
         runtime_function_path && runtime_function_path[0] &&
         param_count > 0 &&
         provenance && provenance[0] == 'r';
}

static const char *registry_value_provenance(const char *a, const char *b, const char *c) {
  if (contains_literal(a, "SelfTest") ||
      contains_literal(a, ".LiveProcessEvent") ||
      contains_literal(b, "SelfTest") ||
      contains_literal(b, ".LiveProcessEvent") ||
      contains_literal(c, "SelfTest") ||
      contains_literal(c, ".LiveProcessEvent")) {
    return "self-test";
  }
  return "runtime";
}

static const char *reflection_descriptor_provenance(const char *a, const char *b, const char *c) {
  return registry_value_provenance(a, b, c);
}

