static size_t config_entry_count;

static size_t cstr_len(const char *value) {
  size_t len = 0;
  if (!value) {
    return 0;
  }
  while (value[len]) {
    ++len;
  }
  return len;
}

static char ascii_lower(char ch) {
  if (ch >= 'A' && ch <= 'Z') {
    return (char)(ch - 'A' + 'a');
  }
  return ch;
}

static int str_equal(const char *a, const char *b) {
  size_t i = 0;
  while (a[i] && b[i]) {
    if (a[i] != b[i]) {
      return 0;
    }
    ++i;
  }
  return a[i] == b[i];
}

static int str_starts_with(const char *value, const char *prefix) {
  size_t i = 0;
  if (!value || !prefix) {
    return 0;
  }
  while (prefix[i]) {
    if (value[i] != prefix[i]) {
      return 0;
    }
    ++i;
  }
  return 1;
}

static long long parse_signed_decimal(const char *value, int *consumed) {
  long long sign = 1;
  long long result = 0;
  size_t i = 0;
  int digits = 0;
  if (consumed) {
    *consumed = 0;
  }
  if (!value) {
    return 0;
  }
  if (value[i] == '-') {
    sign = -1;
    ++i;
  } else if (value[i] == '+') {
    ++i;
  }
  while (value[i] >= '0' && value[i] <= '9') {
    result = result * 10 + (long long)(value[i] - '0');
    ++i;
    ++digits;
  }
  if (consumed) {
    *consumed = digits > 0 ? (int)i : 0;
  }
  return result * sign;
}

static double parse_simple_double(const char *value, int *consumed) {
  double sign = 1.0;
  double result = 0.0;
  double scale = 0.1;
  size_t i = 0;
  int digits = 0;
  if (consumed) {
    *consumed = 0;
  }
  if (!value) {
    return 0.0;
  }
  if (value[i] == '-') {
    sign = -1.0;
    ++i;
  } else if (value[i] == '+') {
    ++i;
  }
  while (value[i] >= '0' && value[i] <= '9') {
    result = result * 10.0 + (double)(value[i] - '0');
    ++i;
    ++digits;
  }
  if (value[i] == '.') {
    ++i;
    while (value[i] >= '0' && value[i] <= '9') {
      result += (double)(value[i] - '0') * scale;
      scale *= 0.1;
      ++i;
      ++digits;
    }
  }
  if (consumed) {
    *consumed = digits > 0 ? (int)i : 0;
  }
  return result * sign;
}

static int str_equal_ci(const char *a, const char *b) {
  size_t i = 0;
  while (a[i] && b[i]) {
    if (ascii_lower(a[i]) != ascii_lower(b[i])) {
      return 0;
    }
    ++i;
  }
  return a[i] == b[i];
}

static int contains_ci(const char *haystack, const char *needle) {
  size_t hay_len = cstr_len(haystack);
  size_t needle_len = cstr_len(needle);
  if (needle_len == 0 || hay_len < needle_len) {
    return 0;
  }
  for (size_t i = 0; i + needle_len <= hay_len; ++i) {
    size_t j = 0;
    while (j < needle_len && ascii_lower(haystack[i + j]) == ascii_lower(needle[j])) {
      ++j;
    }
    if (j == needle_len) {
      return 1;
    }
  }
  return 0;
}

static const char *find_last_char(const char *value, char needle) {
  const char *found = 0;
  if (!value) {
    return 0;
  }
  for (size_t i = 0; value[i]; ++i) {
    if (value[i] == needle) {
      found = value + i;
    }
  }
  return found;
}

static char *find_substring(char *value, const char *needle) {
  size_t value_len = cstr_len(value);
  size_t needle_len = cstr_len(needle);
  if (!value || !needle || needle_len == 0 || value_len < needle_len) {
    return 0;
  }
  for (size_t i = 0; i + needle_len <= value_len; ++i) {
    size_t j = 0;
    while (j < needle_len && value[i + j] == needle[j]) {
      ++j;
    }
    if (j == needle_len) {
      return value + i;
    }
  }
  return 0;
}

static void copy_string(char *dst, size_t dst_size, const char *src) {
  if (dst_size == 0) {
    return;
  }
  size_t i = 0;
  while (src && src[i] && i + 1 < dst_size) {
    dst[i] = src[i];
    ++i;
  }
  dst[i] = '\0';
}

static void copy_hex_string(char *dst, size_t dst_size, unsigned long long value) {
  static const char hex[] = "0123456789abcdef";
  char digits[2 + sizeof(value) * 2 + 1];
  size_t count = 0;
  if (!dst || dst_size == 0) {
    return;
  }
  digits[count++] = '0';
  digits[count++] = 'x';
  int started = 0;
  for (int shift = (int)(sizeof(value) * 8 - 4); shift >= 0; shift -= 4) {
    unsigned int nibble = (unsigned int)((value >> shift) & 0xfULL);
    if (nibble || started || shift == 0) {
      digits[count++] = hex[nibble];
      started = 1;
    }
  }
  digits[count] = '\0';
  copy_string(dst, dst_size, digits);
}

static void export_append_char_to_buffer(char *dst, size_t dst_size, size_t *len, char ch) {
  if (!dst || !len || *len + 1 >= dst_size) {
    return;
  }
  dst[(*len)++] = ch;
  dst[*len] = '\0';
}

static void export_append_string_to_buffer(char *dst, size_t dst_size, size_t *len, const char *src) {
  if (!src) {
    return;
  }
  while (*src) {
    export_append_char_to_buffer(dst, dst_size, len, *src++);
  }
}

static void export_append_unsigned_to_buffer(char *dst, size_t dst_size, size_t *len, unsigned long long value) {
  char digits[32];
  size_t count = 0;
  if (value == 0) {
    export_append_char_to_buffer(dst, dst_size, len, '0');
    return;
  }
  while (value > 0 && count < sizeof(digits)) {
    digits[count++] = (char)('0' + (value % 10ULL));
    value /= 10ULL;
  }
  while (count > 0) {
    export_append_char_to_buffer(dst, dst_size, len, digits[--count]);
  }
}

static void export_format_signed_dec(char *dst, size_t dst_size, long long value) {
  if (!dst || dst_size == 0) {
    return;
  }
  dst[0] = '\0';
  size_t len = 0;
  if (value < 0) {
    export_append_char_to_buffer(dst, dst_size, &len, '-');
    export_append_unsigned_to_buffer(dst, dst_size, &len, (unsigned long long)(-(value + 1)) + 1ULL);
    return;
  }
  export_append_unsigned_to_buffer(dst, dst_size, &len, (unsigned long long)value);
}

static void export_format_fixed3(char *dst, size_t dst_size, double value) {
  if (!dst || dst_size == 0) {
    return;
  }
  dst[0] = '\0';
  size_t len = 0;
  if (value < 0.0) {
    export_append_char_to_buffer(dst, dst_size, &len, '-');
    value = -value;
  }
  unsigned long long scaled = (unsigned long long)(value * 1000.0 + 0.5);
  unsigned long long whole = scaled / 1000ULL;
  unsigned fraction = (unsigned)(scaled % 1000ULL);
  export_append_unsigned_to_buffer(dst, dst_size, &len, whole);
  export_append_char_to_buffer(dst, dst_size, &len, '.');
  export_append_char_to_buffer(dst, dst_size, &len, (char)('0' + ((fraction / 100U) % 10U)));
  export_append_char_to_buffer(dst, dst_size, &len, (char)('0' + ((fraction / 10U) % 10U)));
  export_append_char_to_buffer(dst, dst_size, &len, (char)('0' + (fraction % 10U)));
}

static char *trim(char *value) {
  while (*value == ' ' || *value == '\t' || *value == '\r' || *value == '\n') {
    ++value;
  }
  size_t len = cstr_len(value);
  while (len > 0) {
    char ch = value[len - 1];
    if (ch != ' ' && ch != '\t' && ch != '\r' && ch != '\n') {
      break;
    }
    value[--len] = '\0';
  }
  return value;
}

static void lower_inplace(char *value) {
  for (size_t i = 0; value[i]; ++i) {
    value[i] = ascii_lower(value[i]);
  }
}

static void safe_value(const char *value, char *out, size_t out_size) {
  if (out_size == 0) {
    return;
  }
  size_t written = 0;
  for (size_t i = 0; value && value[i] && written + 1 < out_size; ++i) {
    unsigned char ch = (unsigned char)value[i];
    if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
        (ch >= '0' && ch <= '9') || ch == '_' || ch == '-' ||
        ch == '.' || ch == '/' || ch == '\\' || ch == ':' || ch == '+') {
      out[written++] = (char)ch;
    } else if (ch >= 32 && ch < 127) {
      out[written++] = '_';
    } else {
      out[written++] = '?';
    }
  }
  out[written] = '\0';
}

static void line_init(Line *line) {
  line->len = 0;
  line->text[0] = '\0';
}

static void line_append_char(Line *line, char ch) {
  if (line->len + 1 >= sizeof(line->text)) {
    return;
  }
  line->text[line->len++] = ch;
  line->text[line->len] = '\0';
}

static void line_append(Line *line, const char *value) {
  for (size_t i = 0; value && value[i]; ++i) {
    line_append_char(line, value[i]);
  }
}

static void line_append_dec(Line *line, unsigned long long value) {
  char digits[32];
  size_t count = 0;
  if (value == 0) {
    line_append_char(line, '0');
    return;
  }
  while (value > 0 && count < sizeof(digits)) {
    digits[count++] = (char)('0' + (value % 10ULL));
    value /= 10ULL;
  }
  while (count > 0) {
    line_append_char(line, digits[--count]);
  }
}

static void line_append_signed_dec(Line *line, long long value) {
  if (value < 0) {
    line_append_char(line, '-');
    line_append_dec(line, (unsigned long long)(-(value + 1)) + 1ULL);
    return;
  }
  line_append_dec(line, (unsigned long long)value);
}

static void line_append_fixed3(Line *line, double value) {
  if (value < 0.0) {
    line_append_char(line, '-');
    value = -value;
  }
  unsigned long long scaled = (unsigned long long)(value * 1000.0 + 0.5);
  unsigned long long whole = scaled / 1000ULL;
  unsigned fraction = (unsigned)(scaled % 1000ULL);
  line_append_dec(line, whole);
  line_append_char(line, '.');
  line_append_char(line, (char)('0' + ((fraction / 100U) % 10U)));
  line_append_char(line, (char)('0' + ((fraction / 10U) % 10U)));
  line_append_char(line, (char)('0' + (fraction % 10U)));
}

static void line_append_hex(Line *line, unsigned long long value) {
  static const char hex[] = "0123456789abcdef";
  char digits[32];
  size_t count = 0;
  line_append(line, "0x");
  if (value == 0) {
    line_append_char(line, '0');
    return;
  }
  while (value > 0 && count < sizeof(digits)) {
    digits[count++] = hex[value & 0xfULL];
    value >>= 4;
  }
  while (count > 0) {
    line_append_char(line, digits[--count]);
  }
}

static void append_two_digits(Line *line, unsigned value) {
  line_append_char(line, (char)('0' + ((value / 10U) % 10U)));
  line_append_char(line, (char)('0' + (value % 10U)));
}

static void append_four_digits(Line *line, unsigned value) {
  line_append_char(line, (char)('0' + ((value / 1000U) % 10U)));
  line_append_char(line, (char)('0' + ((value / 100U) % 10U)));
  line_append_char(line, (char)('0' + ((value / 10U) % 10U)));
  line_append_char(line, (char)('0' + (value % 10U)));
}

static int module_dir_path(char *out, size_t out_size, const char *leaf) {
  if (out_size == 0) {
    return 0;
  }
  static char module_path[1024];
  module_path[0] = '\0';
  if (GetModuleFileNameA(self_module, module_path, sizeof(module_path)) == 0) {
    out[0] = '\0';
    return 0;
  }
  size_t len = cstr_len(module_path);
  size_t cut = len;
  while (cut > 0 && module_path[cut - 1] != '\\' && module_path[cut - 1] != '/') {
    --cut;
  }
  size_t written = 0;
  while (written < cut && written + 1 < out_size) {
    out[written] = module_path[written];
    ++written;
  }
  for (size_t i = 0; leaf && leaf[i] && written + 1 < out_size; ++i) {
    out[written++] = leaf[i];
  }
  out[written] = '\0';
  return written > 0;
}

static int module_path_with_suffix(char *out, size_t out_size, const char *suffix) {
  if (out_size == 0) {
    return 0;
  }
  if (GetModuleFileNameA(self_module, out, (DWORD)out_size) == 0) {
    out[0] = '\0';
    return 0;
  }
  size_t written = cstr_len(out);
  for (size_t i = 0; suffix && suffix[i] && written + 1 < out_size; ++i) {
    out[written++] = suffix[i];
  }
  out[written] = '\0';
  return written > 0;
}

static int read_config_file(const char *path, char *buffer, size_t buffer_size, size_t *length) {
  if (buffer_size == 0) {
    return 0;
  }
  HANDLE file = CreateFileA(
    path,
    GENERIC_READ,
    FILE_SHARE_READ | FILE_SHARE_WRITE | FILE_SHARE_DELETE,
    0,
    OPEN_EXISTING,
    FILE_ATTRIBUTE_NORMAL,
    0
  );
  if (file == INVALID_HANDLE_VALUE) {
    return 0;
  }
  DWORD got = 0;
  BOOL ok = ReadFile(file, buffer, (DWORD)(buffer_size - 1), &got, 0);
  CloseHandle(file);
  if (!ok) {
    return 0;
  }
  buffer[got] = '\0';
  if (length) {
    *length = (size_t)got;
  }
  return 1;
}

static void config_add(const char *key, const char *value) {
  if (!key || !key[0] || config_entry_count >= MAX_CONFIG_ENTRIES) {
    return;
  }
  for (size_t i = 0; i < config_entry_count; ++i) {
    if (str_equal(config_entries[i].key, key)) {
      copy_string(config_entries[i].value, sizeof(config_entries[i].value), value);
      return;
    }
  }
  copy_string(config_entries[config_entry_count].key, sizeof(config_entries[config_entry_count].key), key);
  copy_string(config_entries[config_entry_count].value, sizeof(config_entries[config_entry_count].value), value);
  ++config_entry_count;
}

static void strip_matching_quotes(char **value) {
  char *raw = *value;
  size_t len = cstr_len(raw);
  if (len >= 2 &&
      ((raw[0] == '"' && raw[len - 1] == '"') || (raw[0] == '\'' && raw[len - 1] == '\''))) {
    raw[len - 1] = '\0';
    *value = raw + 1;
  }
}

static void parse_config_buffer(char *buffer) {
  char *line = buffer;
  while (line && *line) {
    char *next = line;
    while (*next && *next != '\n') {
      ++next;
    }
    if (*next) {
      *next = '\0';
      ++next;
    } else {
      next = 0;
    }

    char *item = trim(line);
    if (item[0] && item[0] != '#') {
      if (item[0] == 'e' && item[1] == 'x' && item[2] == 'p' && item[3] == 'o' &&
          item[4] == 'r' && item[5] == 't' && (item[6] == ' ' || item[6] == '\t')) {
        item = trim(item + 7);
      }
      char *separator = item;
      while (*separator && *separator != '=') {
        ++separator;
      }
      if (*separator == '=') {
        *separator = '\0';
        char *key = trim(item);
        char *value = trim(separator + 1);
        strip_matching_quotes(&value);
        config_add(key, value);
      }
    }
    line = next;
  }
}

static int load_config_path(const char *path) {
  static char buffer[MAX_CONFIG_BYTES];
  size_t length = 0;
  if (!read_config_file(path, buffer, sizeof(buffer), &length) || length == 0) {
    return 0;
  }
  config_file_found = 1;
  copy_string(config_path, sizeof(config_path), path);
  parse_config_buffer(buffer);
  return 1;
}

static void load_probe_config_once(void) {
  if (config_loaded) {
    return;
  }
  config_loaded = 1;

  static char path[1024];
  if (module_dir_path(path, sizeof(path), "dune-win-client-probe.env") && load_config_path(path)) {
    return;
  }
  if (module_path_with_suffix(path, sizeof(path), ".env")) {
    load_config_path(path);
  }
}

static DWORD config_get(const char *name, char *buffer, size_t size) {
  load_probe_config_once();
  for (size_t i = 0; i < config_entry_count; ++i) {
    if (str_equal(config_entries[i].key, name)) {
      copy_string(buffer, size, config_entries[i].value);
      return (DWORD)cstr_len(config_entries[i].value);
    }
  }
  return 0;
}

static DWORD env_get(const char *name, char *buffer, size_t size) {
  if (size == 0) {
    return 0;
  }
  DWORD got = GetEnvironmentVariableA(name, buffer, (DWORD)size);
  if (got >= size) {
    buffer[size - 1] = '\0';
    return got;
  }
  if (got > 0) {
    return got;
  }
  return config_get(name, buffer, size);
}

static void default_log_path(char *buffer, size_t size) {
  if (env_get("DUNE_WIN_CLIENT_PROBE_LOG", buffer, size) > 0) {
    return;
  }
  copy_string(buffer, size, "Z:\\tmp\\dune-win-client-probe-loader.log");
}

static void emit_line(Line *line) {
  static char path[512];
  default_log_path(path, sizeof(path));

  HANDLE file = CreateFileA(
    path,
    FILE_APPEND_DATA,
    FILE_SHARE_READ | FILE_SHARE_WRITE | FILE_SHARE_DELETE,
    0,
    OPEN_ALWAYS,
    FILE_ATTRIBUTE_NORMAL,
    0
  );
  if (file == INVALID_HANDLE_VALUE) {
    return;
  }

  static Line prefix;
  line_init(&prefix);
  SYSTEMTIME_WIN st;
  GetSystemTime(&st);
  append_four_digits(&prefix, st.wYear);
  line_append_char(&prefix, '-');
  append_two_digits(&prefix, st.wMonth);
  line_append_char(&prefix, '-');
  append_two_digits(&prefix, st.wDay);
  line_append_char(&prefix, 'T');
  append_two_digits(&prefix, st.wHour);
  line_append_char(&prefix, ':');
  append_two_digits(&prefix, st.wMinute);
  line_append_char(&prefix, ':');
  append_two_digits(&prefix, st.wSecond);
  line_append(&prefix, "Z pid=");
  line_append_dec(&prefix, GetCurrentProcessId());
  line_append(&prefix, " loader=win-client ");

  DWORD written = 0;
  WriteFile(file, prefix.text, (DWORD)prefix.len, &written, 0);
  WriteFile(file, line->text, (DWORD)line->len, &written, 0);
  WriteFile(file, "\r\n", 2, &written, 0);
  CloseHandle(file);
}

static int parse_unsigned(const char *raw, int base, unsigned long long *out) {
  if (!raw || !raw[0]) {
    return 0;
  }
  if (base == 16 && raw[0] == '0' && (raw[1] == 'x' || raw[1] == 'X')) {
    raw += 2;
  }
  unsigned long long parsed = 0;
  for (size_t i = 0; raw[i]; ++i) {
    int digit = -1;
    if (raw[i] >= '0' && raw[i] <= '9') {
      digit = raw[i] - '0';
    } else if (base == 16 && raw[i] >= 'a' && raw[i] <= 'f') {
      digit = raw[i] - 'a' + 10;
    } else if (base == 16 && raw[i] >= 'A' && raw[i] <= 'F') {
      digit = raw[i] - 'A' + 10;
    }
    if (digit < 0 || digit >= base) {
      return 0;
    }
    parsed = parsed * (unsigned long long)base + (unsigned long long)digit;
  }
  *out = parsed;
  return 1;
}

static int parse_unsigned_auto(const char *raw, unsigned long long *out) {
  if (!raw || !raw[0]) {
    return 0;
  }
  int base = 10;
  if (raw[0] == '0' && (raw[1] == 'x' || raw[1] == 'X')) {
    base = 16;
  } else {
    for (size_t i = 0; raw[i]; ++i) {
      if ((raw[i] >= 'a' && raw[i] <= 'f') || (raw[i] >= 'A' && raw[i] <= 'F')) {
        base = 16;
        break;
      }
    }
  }
  return parse_unsigned(raw, base, out);
}

static int env_bool(const char *name, int default_value) {
  char raw[32];
  if (env_get(name, raw, sizeof(raw)) == 0 || raw[0] == '\0') {
    return default_value;
  }
  lower_inplace(raw);
  return str_equal(raw, "1") || str_equal(raw, "true") || str_equal(raw, "yes") || str_equal(raw, "on");
}

static size_t env_size(const char *name, size_t default_value) {
  static char raw[64];
  unsigned long long parsed = 0;
  if (env_get(name, raw, sizeof(raw)) == 0 || !parse_unsigned(raw, 10, &parsed) || parsed == 0) {
    return default_value;
  }
  return (size_t)parsed;
}

static size_t env_size_auto(const char *name, size_t default_value) {
  char raw[64];
  unsigned long long parsed = 0;
  if (env_get(name, raw, sizeof(raw)) == 0 || !parse_unsigned_auto(raw, &parsed) || parsed == 0) {
    return default_value;
  }
  return (size_t)parsed;
}

static uintptr_t env_address_auto(const char *name, uintptr_t default_value) {
  char raw[64];
  unsigned long long parsed = 0;
  if (env_get(name, raw, sizeof(raw)) == 0 || !parse_unsigned_auto(raw, &parsed) || parsed == 0) {
    return default_value;
  }
  return (uintptr_t)parsed;
}

static int env_int(const char *name, int default_value) {
  char raw[64];
  unsigned long long parsed = 0;
  if (env_get(name, raw, sizeof(raw)) == 0 || !parse_unsigned(raw, 10, &parsed) || parsed > 3600ULL) {
    return default_value;
  }
  return (int)parsed;
}

static void add_needle(char needles[][MAX_NEEDLE_LEN], size_t *count, const char *needle) {
  if (!needle || !needle[0] || *count >= MAX_NEEDLES) {
    return;
  }
  for (size_t i = 0; i < *count; ++i) {
    if (str_equal(needles[i], needle)) {
      return;
    }
  }
  copy_string(needles[*count], MAX_NEEDLE_LEN, needle);
  ++(*count);
}

static void append_preset(const char *preset, char needles[][MAX_NEEDLE_LEN], size_t *count) {
  if (str_equal(preset, "core")) {
    const char *items[] = {"DuneSandbox", "DuneSandbox-Win64-Shipping", "/Script/DuneSandbox", "/Script/Engine", "EngineVersion"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  } else if (str_equal(preset, "ue") || str_equal(preset, "unreal")) {
    static const char *const items[] = {"GUObjectArray", "GObjectArray", "GObjects", "FUObjectArray", "FNamePool", "NamePoolData", "GName", "GNames", "GWorld", "GEngine", "/Script/Engine.World", "/Script/Engine.Engine", "WorldContext", "ProcessEvent", "StaticFindObject", "CallFunctionByNameWithArguments", "CallFunctionByName", "ProcessConsoleExec", "ULocalPlayerExec", "StaticLoadObject", "StaticLoadClass", "LoadObject", "LoadPackage", "ResolveName", "LoadAsset", "LoadClass", "UObject", "UFunction", "UClass", "FProperty", "FObjectProperty", "FArrayProperty", "FBoolProperty", "FStructProperty", "UStruct", "UEnum"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  } else if (str_equal(preset, "client")) {
    const char *items[] = {"LocalPlayer", "PlayerController", "GameViewport", "ViewportClient", "ConsoleKey", "ConsoleKeys", "InputSettings", "ClientTravel", "ClientRestart"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  } else if (str_equal(preset, "cheat")) {
    const char *items[] = {"CheatManager", "CheatClass", "/Script/Engine.CheatManager", "EnableCheats", "AdminLogin", "ServerCheat", "ClientMessage"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  } else if (str_equal(preset, "brt")) {
    const char *items[] = {"m_BaseBackupToolMapRestriction", "ServerRequestBaseBackup", "BaseBackupActionPlace", "UGameItemBaseBackupToolActions", "PerformCanBePlaced", "Fail_InvalidMap", "BaseBackupTool"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  } else if (str_equal(preset, "deep-desert")) {
    const char *items[] = {"DeepDesert", "DeepDesert_1", "m_DeepDesertGameplay", "m_ShiftingSands", "m_PerMapSystemSettings", "m_SpiceFieldTypeSettings"};
    for (size_t i = 0; i < sizeof(items) / sizeof(items[0]); ++i) add_needle(needles, count, items[i]);
  }
}

static void parse_delimited_needles(char *raw, char delimiter, char needles[][MAX_NEEDLE_LEN], size_t *count, int presets) {
  char *start = raw;
  while (start && *start) {
    char *end = start;
    while (*end && *end != delimiter) {
      ++end;
    }
    int has_delimiter = *end == delimiter;
    if (*end) {
      *end = '\0';
    }
    char *item = trim(start);
    if (item[0]) {
      if (presets) {
        lower_inplace(item);
        append_preset(item, needles, count);
      } else {
        add_needle(needles, count, item);
      }
    }
    start = has_delimiter ? end + 1 : 0;
  }
}

static void collect_needles(char needles[][MAX_NEEDLE_LEN], size_t *count) {
  static char presets[2048];
  static char extras[4096];
  DWORD got_presets = env_get("DUNE_WIN_CLIENT_PROBE_SCAN_PRESETS", presets, sizeof(presets));
  DWORD got_extras = env_get("DUNE_WIN_CLIENT_PROBE_SCAN_STRINGS", extras, sizeof(extras));
  if (got_presets == 0 && got_extras == 0) {
    copy_string(presets, sizeof(presets), "core,ue,client,cheat,brt,deep-desert");
    got_presets = (DWORD)cstr_len(presets);
  }
  if (got_presets > 0) {
    parse_delimited_needles(presets, ',', needles, count, 1);
  }
  if (got_extras > 0) {
    parse_delimited_needles(extras, ';', needles, count, 0);
  }
}

static char *next_token(char **cursor) {
  char *p = *cursor;
  while (*p == ' ' || *p == '\t' || *p == '\r' || *p == '\n') {
    ++p;
  }
  if (!*p) {
    *cursor = p;
    return 0;
  }
  char *start = p;
  while (*p && *p != ' ' && *p != '\t' && *p != '\r' && *p != '\n') {
    ++p;
  }
  if (*p) {
    *p++ = '\0';
  }
  *cursor = p;
  return start;
}

static void parse_pattern_item(char *item, BytePattern *patterns, size_t *count) {
  if (*count >= MAX_PATTERNS) {
    return;
  }
  char *separator = item;
  while (*separator && *separator != '=' && *separator != ':') {
    ++separator;
  }
  if (!*separator) {
    return;
  }
  *separator = '\0';
  char *name = trim(item);
  char *body = trim(separator + 1);
  if (!name[0] || !body[0]) {
    return;
  }

  BytePattern *pattern = &patterns[*count];
  for (size_t i = 0; i < sizeof(*pattern); ++i) {
    ((char *)pattern)[i] = 0;
  }
  copy_string(pattern->name, sizeof(pattern->name), name);

  char *cursor = body;
  char *token = 0;
  while ((token = next_token(&cursor)) != 0) {
    if (pattern->length >= MAX_PATTERN_BYTES) {
      pattern->length = 0;
      return;
    }
    if (str_equal(token, "?") || str_equal(token, "??")) {
      pattern->bytes[pattern->length++] = -1;
      continue;
    }
    unsigned long long parsed = 0;
    if (!parse_unsigned(token, 16, &parsed) || parsed > 255ULL) {
      pattern->length = 0;
      return;
    }
    pattern->bytes[pattern->length++] = (int)parsed;
  }
  if (pattern->length > 0) {
    ++(*count);
  }
}

static void collect_patterns(BytePattern *patterns, size_t *count) {
  static char raw[4096];
  if (env_get("DUNE_WIN_CLIENT_PROBE_SCAN_SIGNATURES", raw, sizeof(raw)) > 0) {
    char *start = raw;
    while (start && *start) {
      char *end = start;
      while (*end && *end != ';' && *end != '\n' && *end != '\r') {
        ++end;
      }
      int has_delimiter = *end != '\0';
      if (*end) {
        *end = '\0';
      }
      char *item = trim(start);
      if (item[0] && item[0] != '#') {
        parse_pattern_item(item, patterns, count);
      }
      start = has_delimiter ? end + 1 : 0;
      while (start && (*start == '\n' || *start == '\r')) {
        ++start;
      }
    }
  }

  static char path[2048];
  if (env_get("DUNE_WIN_CLIENT_PROBE_SCAN_SIGNATURES_FILE", path, sizeof(path)) == 0) {
    return;
  }
  static char file_raw[MAX_SIGNATURE_FILE_BYTES + 1];
  size_t length = 0;
  static char safe_path[2048];
  safe_value(path, safe_path, sizeof(safe_path));
  if (!read_config_file(path, file_raw, sizeof(file_raw), &length)) {
    static Line line;
    line_init(&line);
    line_append(&line, "event=signature-file-skip reason=open-failed path=");
    line_append(&line, safe_path);
    emit_line(&line);
    return;
  }
  size_t before = *count;
  char *start = file_raw;
  while (start && *start) {
    char *end = start;
    while (*end && *end != ';' && *end != '\n' && *end != '\r') {
      ++end;
    }
    int has_delimiter = *end != '\0';
    if (*end) {
      *end = '\0';
    }
    char *item = trim(start);
    if (item[0] && item[0] != '#') {
      parse_pattern_item(item, patterns, count);
    }
    start = has_delimiter ? end + 1 : 0;
    while (start && (*start == '\n' || *start == '\r')) {
      ++start;
    }
  }
  static Line line;
  line_init(&line);
  line_append(&line, "event=signature-file path=");
  line_append(&line, safe_path);
  line_append(&line, " bytes=");
  line_append_dec(&line, length);
  line_append(&line, " patterns=");
  line_append_dec(&line, *count - before);
  emit_line(&line);
}

static const unsigned char *find_pattern(const unsigned char *begin, const unsigned char *end, const BytePattern *pattern);
static void parse_filters(char filters[][MAX_NEEDLE_LEN], size_t *count);
static int module_path_matches(const char *module_path, const char *exe_path, char filters[][MAX_NEEDLE_LEN], size_t filter_count);

static int is_loader_module_path(const char *path) {
  char normalized[1024];
  size_t written = 0;
  if (!path || !path[0]) {
    return 0;
  }
  for (size_t i = 0; path[i] && written + 1 < sizeof(normalized); ++i) {
    char ch = path[i];
    if (ch == '\\') {
      ch = '/';
    } else if (ch >= 'A' && ch <= 'Z') {
      ch = (char)(ch - 'A' + 'a');
    }
    normalized[written++] = ch;
  }
  normalized[written] = '\0';
  return contains_ci(normalized, "dune_client_probe_loader") ||
         contains_ci(normalized, "dune_server_probe_loader") ||
         contains_ci(normalized, "dune_win_client_probe_loader") ||
         contains_ci(normalized, "linux-client-loader") ||
         contains_ci(normalized, "linux-server-loader") ||
         contains_ci(normalized, "windows-client-loader") ||
         contains_ci(normalized, "libdune_") ||
         contains_ci(normalized, "/version.dll");
}

static int address_is_target_image(uintptr_t address) {
  MEMORY_BASIC_INFORMATION_WIN64 mbi;
  char module_path[1024];
  if (!address || VirtualQuery((const void *)address, &mbi, sizeof(mbi)) == 0 ||
      !mbi.AllocationBase ||
      GetModuleFileNameA((HMODULE)mbi.AllocationBase, module_path, sizeof(module_path)) == 0) {
    return 0;
  }
  return !is_loader_module_path(module_path);
}

static uintptr_t resolve_target_rva_env(const char *env_name) {
  uintptr_t rva = env_address_auto(env_name, 0);
  if (!rva) {
    return 0;
  }
  uintptr_t image_base = (uintptr_t)GetModuleHandleA(0);
  static Line line;
  if (!image_base) {
    line_init(&line);
    line_append(&line, "event=ue-code-target name=");
    line_append(&line, env_name);
    line_append(&line, " status=base-missing rva=");
    line_append_hex(&line, rva);
    emit_line(&line);
    return 0;
  }
  uintptr_t target = image_base + rva;
  MEMORY_BASIC_INFORMATION_WIN64 mbi;
  SIZE_T got = VirtualQuery((const void *)target, &mbi, sizeof(mbi));
  if (!got || mbi.State != MEM_COMMIT || !address_is_target_image(target)) {
    line_init(&line);
    line_append(&line, "event=ue-code-target name=");
    line_append(&line, env_name);
    line_append(&line, " status=target-unmapped target=");
    line_append_hex(&line, target);
    line_append(&line, " rva=");
    line_append_hex(&line, rva);
    emit_line(&line);
    return 0;
  }
  static char module_path[1024];
  static char safe_module_path[1024];
  module_path[0] = '\0';
  safe_module_path[0] = '\0';
  GetModuleFileNameA((HMODULE)mbi.AllocationBase, module_path, sizeof(module_path));
  safe_value(module_path, safe_module_path, sizeof(safe_module_path));
  line_init(&line);
  line_append(&line, "event=ue-code-target name=");
  line_append(&line, env_name);
  line_append(&line, " status=resolved target=");
  line_append_hex(&line, target);
  line_append(&line, " rva=");
  line_append_hex(&line, rva);
  line_append(&line, " allocationBase=");
  line_append_hex(&line, (uintptr_t)mbi.AllocationBase);
  line_append(&line, " protect=");
  line_append_hex(&line, mbi.Protect);
  line_append(&line, " module=");
  line_append(&line, safe_module_path);
  emit_line(&line);
  return target;
}

static const char *ue_anchor_group_for_name(const char *name) {
  if (!name) {
    return "unknown";
  }
  if (cstr_len(name) >= 8 && name[0] == 'S' && name[1] == 'e' && name[2] == 'l' && name[3] == 'f' &&
      name[4] == 'T' && name[5] == 'e' && name[6] == 's' && name[7] == 't') {
    return "self-test";
  }
  if (str_equal(name, "FNamePool") || str_equal(name, "RuntimeFNamePool") ||
      contains_ci(name, "RuntimeFNamePoolCandidate") ||
      str_equal(name, "NamePoolData") ||
      str_equal(name, "GName") || str_equal(name, "GNames")) {
    return "names";
  }
  if (str_equal(name, "GUObjectArray") || str_equal(name, "RuntimeGUObjectArray") ||
      contains_ci(name, "RuntimeGUObjectArrayCandidate") ||
      str_equal(name, "GObjectArray") ||
      str_equal(name, "GObjects") || str_equal(name, "FUObjectArray")) {
    return "objects";
  }
  if (str_equal(name, "GWorld") || str_equal(name, "GEngine")) {
    return "world";
  }
  if (str_equal(name, "ProcessEvent") || str_equal(name, "StaticFindObject") ||
      str_equal(name, "CallFunctionByNameWithArguments") || str_equal(name, "CallFunctionByName")) {
    return "dispatch";
  }
  if (str_equal(name, "StaticLoadObject") || str_equal(name, "StaticLoadClass") ||
      str_equal(name, "LoadObject") ||
      str_equal(name, "LoadPackage") || str_equal(name, "ResolveName") ||
      str_equal(name, "LoadAsset") || str_equal(name, "LoadClass")) {
    return "package";
  }
  if (str_equal(name, "UObject") || str_equal(name, "UFunction") || str_equal(name, "UClass") ||
      str_equal(name, "FProperty") || str_equal(name, "FObjectProperty") ||
      str_equal(name, "FArrayProperty") || str_equal(name, "FBoolProperty") ||
      str_equal(name, "FStructProperty") || str_equal(name, "UStruct") || str_equal(name, "UEnum")) {
    return "reflection";
  }
  if (str_equal(name, "CheatManager") || str_equal(name, "CheatClass") ||
      str_equal(name, "EnableCheats") || str_equal(name, "AdminLogin")) {
    return "cheat";
  }
  if (str_equal(name, "ServerRequestBaseBackup") || str_equal(name, "BaseBackupActionPlace") ||
      str_equal(name, "PerformCanBePlaced") || str_equal(name, "Fail_InvalidMap")) {
    return "brt";
  }
  if (str_equal(name, "DeepDesert") || str_equal(name, "DeepDesert_1") ||
      str_equal(name, "m_DeepDesertGameplay")) {
    return "deep-desert";
  }
  return "unknown";
}

static void parse_ue_anchor_item(char *item, UeAnchor *anchors, size_t *count) {
  if (*count >= MAX_UE_ANCHORS) {
    return;
  }
  char *separator = item;
  while (*separator && *separator != '=' && *separator != ':') {
    ++separator;
  }
  if (!*separator) {
    static char safe_item[256];
    safe_value(item, safe_item, sizeof(safe_item));
    static Line line;
    line_init(&line);
    line_append(&line, "event=ue-anchor-skip reason=missing-address item=");
    line_append(&line, safe_item);
    emit_line(&line);
    return;
  }
  *separator = '\0';
  char *name = trim(item);
  char *raw_address = trim(separator + 1);
  unsigned long long parsed = 0;
  if (!name[0] || !parse_unsigned(raw_address, 16, &parsed)) {
    static char safe_name[256];
    safe_value(name, safe_name, sizeof(safe_name));
    static Line line;
    line_init(&line);
    line_append(&line, "event=ue-anchor-skip reason=bad-address name=");
    line_append(&line, safe_name);
    emit_line(&line);
    return;
  }
  copy_string(anchors[*count].name, sizeof(anchors[*count].name), name);
  anchors[*count].address = (uintptr_t)parsed;
  ++(*count);
}

static void log_ue_candidate_global(
  const char *name,
  const char *status,
  uintptr_t address,
  unsigned long long image_offset,
  int absolute,
  int runtime_private_rva,
  const char *reason
) {
  static char safe_name[256];
  safe_value(name ? name : "", safe_name, sizeof(safe_name));
  static Line line;
  line_init(&line);
  line_append(&line, "event=ue-candidate-global name=");
  line_append(&line, safe_name);
  line_append(&line, " status=");
  line_append(&line, status);
  if (address) {
    line_append(&line, " address=");
    line_append_hex(&line, address);
  }
  line_append(&line, " imageOffset=");
  line_append_hex(&line, image_offset);
  line_append(&line, " absolute=");
  line_append(&line, absolute ? "true" : "false");
  line_append(&line, " runtimePrivateRva=");
  line_append(&line, runtime_private_rva ? "true" : "false");
  if (reason && reason[0]) {
    line_append(&line, " reason=");
    line_append(&line, reason);
  }
  emit_line(&line);
}

static int readable_protect(DWORD protect);
static int writable_protect(DWORD protect);

static int resolve_runtime_private_rva(unsigned long long parsed, uintptr_t *address_out) {
  if (!address_out) {
    return 0;
  }
  uintptr_t resolved = 0;
  size_t matches = 0;
  uintptr_t cursor = 0x10000;
  while (cursor < (uintptr_t)-0x10000) {
    MEMORY_BASIC_INFORMATION_WIN64 mbi;
    SIZE_T got = VirtualQuery((const void *)cursor, &mbi, sizeof(mbi));
    if (!got || mbi.RegionSize == 0) {
      cursor += 0x10000;
      continue;
    }
    uintptr_t base = (uintptr_t)mbi.BaseAddress;
    uintptr_t next = base + (uintptr_t)mbi.RegionSize;
    if (next <= cursor) {
      break;
    }
    uintptr_t allocation_base = (uintptr_t)mbi.AllocationBase;
    if (mbi.State == MEM_COMMIT && mbi.Type == MEM_PRIVATE &&
        readable_protect(mbi.Protect) && writable_protect(mbi.Protect) &&
        allocation_base != 0 && parsed <= (unsigned long long)((uintptr_t)-1 - allocation_base)) {
      uintptr_t candidate = allocation_base + (uintptr_t)parsed;
      if (candidate >= base && candidate < next) {
        resolved = candidate;
        ++matches;
        if (matches > 1) {
          return -1;
        }
      }
    }
    cursor = next;
  }
  if (matches == 1) {
    *address_out = resolved;
    return 1;
  }
  return 0;
}

static void parse_ue_candidate_global_item(char *item, UeAnchor *anchors, size_t *count, uintptr_t image_base) {
  if (*count >= MAX_UE_ANCHORS) {
    return;
  }
  char *separator = item;
  while (*separator && *separator != '=') {
    ++separator;
  }
  if (!*separator) {
    log_ue_candidate_global(item, "invalid", 0, 0, 0, 0, "missing-equals");
    return;
  }
  *separator = '\0';
  char *name = trim(item);
  char *raw_address = trim(separator + 1);
  unsigned long long parsed = 0;
  if (!name[0] || !parse_unsigned_auto(raw_address, &parsed)) {
    log_ue_candidate_global(name, "invalid", 0, 0, 0, 0, "bad-address");
    return;
  }
  int absolute = 0;
  int runtime_private_rva = 0;
  size_t name_len = cstr_len(name);
  const char absolute_suffix[] = "@addr";
  const char private_rva_suffix[] = "@private-rva";
  size_t absolute_suffix_len = cstr_len(absolute_suffix);
  size_t private_rva_suffix_len = cstr_len(private_rva_suffix);
  if (name_len > absolute_suffix_len && str_equal(name + name_len - absolute_suffix_len, absolute_suffix)) {
    absolute = 1;
    name[name_len - absolute_suffix_len] = '\0';
  } else if (name_len > private_rva_suffix_len &&
             str_equal(name + name_len - private_rva_suffix_len, private_rva_suffix)) {
    runtime_private_rva = 1;
    name[name_len - private_rva_suffix_len] = '\0';
  }
  uintptr_t address = absolute ? (uintptr_t)parsed : image_base + (uintptr_t)parsed;
  if (runtime_private_rva) {
    int private_rva_status = resolve_runtime_private_rva(parsed, &address);
    if (private_rva_status < 0) {
      log_ue_candidate_global(name, "runtime-private-rva-ambiguous", 0, parsed, 0, 1, "");
      return;
    }
    if (private_rva_status == 0) {
      log_ue_candidate_global(name, "runtime-private-rva-missing", 0, parsed, 0, 1, "");
      return;
    }
  }
  if (!absolute && !runtime_private_rva && image_base == 0) {
    log_ue_candidate_global(name, "base-missing", 0, parsed, 0, 0, "");
    return;
  }
  copy_string(anchors[*count].name, sizeof(anchors[*count].name), name);
  anchors[*count].address = address;
  ++(*count);
  log_ue_candidate_global(name, "added", address, parsed, absolute, runtime_private_rva, "");
}

static size_t collect_ue_candidate_global_anchors(UeAnchor *anchors, size_t count) {
  static char raw[16384];
  if (env_get("DUNE_WIN_CLIENT_PROBE_UE_CANDIDATE_GLOBALS", raw, sizeof(raw)) == 0) {
    return count;
  }
  uintptr_t image_base = (uintptr_t)GetModuleHandleA(0);
  char *start = raw;
  while (start && *start) {
    char *end = start;
    while (*end && *end != ';' && *end != '\n' && *end != '\r') {
      ++end;
    }
    int has_delimiter = *end != '\0';
    if (*end) {
      *end = '\0';
    }
    char *item = trim(start);
    if (item[0] && item[0] != '#') {
      parse_ue_candidate_global_item(item, anchors, &count, image_base);
    }
    start = has_delimiter ? end + 1 : 0;
  }
  return count;
}

static void seed_self_test_fname_entry(uint32_t comparison_index, const char *name, uint32_t *cursor) {
  if (!name) {
    return;
  }
  size_t name_len = cstr_len(name);
  uint16_t header = (uint16_t)(name_len << 1);
  size_t entry_offset = (size_t)comparison_index * DEFAULT_UE_FNAME_STRIDE;
  size_t entry_end = entry_offset + sizeof(header) + name_len;
  if (entry_end + 1 >= sizeof(ue_self_test_fname_block)) {
    return;
  }
  ue_self_test_fname_block[entry_offset] = (unsigned char)(header & 0xffU);
  ue_self_test_fname_block[entry_offset + 1] = (unsigned char)((header >> 8) & 0xffU);
  for (size_t i = 0; i < name_len; ++i) {
    ue_self_test_fname_block[entry_offset + sizeof(header) + i] = (unsigned char)name[i];
  }
  if (cursor && entry_end > *cursor) {
    *cursor = (uint32_t)entry_end;
  }
}

