static UeFNameOptions ue_fname_options(void) {
  UeFNameOptions options;
  options.pool_address = env_address_auto("DUNE_WIN_CLIENT_PROBE_UE_FNAME_POOL", 0);
  if (!options.pool_address) {
    options.pool_address = env_address_auto("DUNE_WIN_CLIENT_PROBE_UE_FNAME_POOL_ADDR", 0);
  }
  options.pool_offset = env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_FNAME_POOL_OFFSET", 0);
  options.blocks_offset = env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_FNAME_BLOCKS_OFFSET", DEFAULT_UE_FNAME_BLOCKS_OFFSET);
  options.stride = env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_FNAME_STRIDE", DEFAULT_UE_FNAME_STRIDE);
  options.max_length = env_size("DUNE_WIN_CLIENT_PROBE_UE_FNAME_MAX_LENGTH", DEFAULT_UE_FNAME_MAX_LENGTH);
  if (options.blocks_offset > 0x4000) {
    options.blocks_offset = DEFAULT_UE_FNAME_BLOCKS_OFFSET;
  }
  if (options.stride == 0 || options.stride > 8) {
    options.stride = DEFAULT_UE_FNAME_STRIDE;
  }
  if (options.max_length == 0 || options.max_length > MAX_UE_FNAME_LENGTH) {
    options.max_length = DEFAULT_UE_FNAME_MAX_LENGTH;
  }
  return options;
}

static UeObjectArrayOptions ue_object_array_options(void) {
  UeObjectArrayOptions options;
  options.array_offset = env_size("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_OFFSET", 0);
  options.item_size = env_size("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_ITEM_SIZE", DEFAULT_UE_OBJECT_ITEM_SIZE);
  options.object_offset = env_size("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_OBJECT_OFFSET", 0);
  options.chunk_size = env_size("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_CHUNK_SIZE", DEFAULT_UE_OBJECT_CHUNK_SIZE);
  options.max_objects = env_size("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_MAX_OBJECTS", DEFAULT_UE_OBJECT_ARRAY_MAX_OBJECTS);
  if (options.item_size < sizeof(uintptr_t) || options.item_size > 256) {
    options.item_size = DEFAULT_UE_OBJECT_ITEM_SIZE;
  }
  if (options.object_offset + sizeof(uintptr_t) > options.item_size) {
    options.object_offset = 0;
  }
  if (options.chunk_size == 0 || options.chunk_size > DEFAULT_UE_OBJECT_CHUNK_SIZE) {
    options.chunk_size = DEFAULT_UE_OBJECT_CHUNK_SIZE;
  }
  if (options.max_objects == 0) {
    options.max_objects = DEFAULT_UE_OBJECT_ARRAY_MAX_OBJECTS;
  } else if (options.max_objects > MAX_UE_OBJECT_ARRAY_SCAN_OBJECTS) {
    options.max_objects = MAX_UE_OBJECT_ARRAY_SCAN_OBJECTS;
  }
  return options;
}

static size_t sane_reflection_offset(size_t value, size_t fallback) {
  return value <= MAX_UE_REFLECTION_SLOT_OFFSET ? value : fallback;
}

static UeReflectionOptions ue_reflection_options(void) {
  UeReflectionOptions options;
  options.next_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_NEXT_OFFSET", DEFAULT_UE_REFLECTION_NEXT_OFFSET),
    DEFAULT_UE_REFLECTION_NEXT_OFFSET
  );
  options.super_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_SUPER_OFFSET", DEFAULT_UE_REFLECTION_SUPER_OFFSET),
    DEFAULT_UE_REFLECTION_SUPER_OFFSET
  );
  options.children_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_CHILDREN_OFFSET", DEFAULT_UE_REFLECTION_CHILDREN_OFFSET),
    DEFAULT_UE_REFLECTION_CHILDREN_OFFSET
  );
  options.child_properties_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_CHILD_PROPERTIES_OFFSET", DEFAULT_UE_REFLECTION_CHILD_PROPERTIES_OFFSET),
    DEFAULT_UE_REFLECTION_CHILD_PROPERTIES_OFFSET
  );
  options.property_link_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_PROPERTY_LINK_OFFSET", DEFAULT_UE_REFLECTION_PROPERTY_LINK_OFFSET),
    DEFAULT_UE_REFLECTION_PROPERTY_LINK_OFFSET
  );
  options.function_link_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_FUNCTION_LINK_OFFSET", DEFAULT_UE_REFLECTION_FUNCTION_LINK_OFFSET),
    DEFAULT_UE_REFLECTION_FUNCTION_LINK_OFFSET
  );
  options.field_next_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_FIELD_NEXT_OFFSET", DEFAULT_UE_REFLECTION_FIELD_NEXT_OFFSET),
    DEFAULT_UE_REFLECTION_FIELD_NEXT_OFFSET
  );
  options.property_array_dim_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_PROPERTY_ARRAY_DIM_OFFSET", DEFAULT_UE_REFLECTION_PROPERTY_ARRAY_DIM_OFFSET),
    DEFAULT_UE_REFLECTION_PROPERTY_ARRAY_DIM_OFFSET
  );
  options.property_element_size_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_PROPERTY_ELEMENT_SIZE_OFFSET", DEFAULT_UE_REFLECTION_PROPERTY_ELEMENT_SIZE_OFFSET),
    DEFAULT_UE_REFLECTION_PROPERTY_ELEMENT_SIZE_OFFSET
  );
  options.property_flags_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_PROPERTY_FLAGS_OFFSET", DEFAULT_UE_REFLECTION_PROPERTY_FLAGS_OFFSET),
    DEFAULT_UE_REFLECTION_PROPERTY_FLAGS_OFFSET
  );
  options.property_offset_internal_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_PROPERTY_OFFSET_INTERNAL_OFFSET", DEFAULT_UE_REFLECTION_PROPERTY_OFFSET_INTERNAL_OFFSET),
    DEFAULT_UE_REFLECTION_PROPERTY_OFFSET_INTERNAL_OFFSET
  );
  options.function_flags_offset = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_FUNCTION_FLAGS_OFFSET", DEFAULT_UE_REFLECTION_FUNCTION_FLAGS_OFFSET),
    DEFAULT_UE_REFLECTION_FUNCTION_FLAGS_OFFSET
  );
  options.container_child_scan_start = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_CONTAINER_CHILD_SCAN_START", DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_START),
    DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_START
  );
  options.container_child_scan_end = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_CONTAINER_CHILD_SCAN_END", DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_END),
    DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_END
  );
  if (options.container_child_scan_end <= options.container_child_scan_start ||
      options.container_child_scan_end - options.container_child_scan_start > 0x100) {
    options.container_child_scan_start = DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_START;
    options.container_child_scan_end = DEFAULT_UE_REFLECTION_CONTAINER_CHILD_SCAN_END;
  }
  options.function_param_root_scan_start = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_FUNCTION_PARAM_ROOT_SCAN_START", DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_START),
    DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_START
  );
  options.function_param_root_scan_end = sane_reflection_offset(
    env_size_auto("DUNE_WIN_CLIENT_PROBE_UE_FUNCTION_PARAM_ROOT_SCAN_END", DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_END),
    DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_END
  );
  if (options.function_param_root_scan_end <= options.function_param_root_scan_start ||
      options.function_param_root_scan_end - options.function_param_root_scan_start > 0x200) {
    options.function_param_root_scan_start = DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_START;
    options.function_param_root_scan_end = DEFAULT_UE_FUNCTION_PARAM_ROOT_SCAN_END;
  }
  options.max_fields = env_size("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_MAX_FIELDS", DEFAULT_UE_REFLECTION_MAX_FIELDS);
  if (options.max_fields == 0 || options.max_fields > MAX_UE_REFLECTION_FIELDS) {
    options.max_fields = DEFAULT_UE_REFLECTION_MAX_FIELDS;
  }
  options.value_max_bytes = env_size("DUNE_WIN_CLIENT_PROBE_UE_REFLECTION_VALUE_MAX_BYTES", DEFAULT_UE_REFLECTION_VALUE_MAX_BYTES);
  if (options.value_max_bytes == 0 || options.value_max_bytes > MAX_UE_REFLECTION_VALUE_BYTES) {
    options.value_max_bytes = DEFAULT_UE_REFLECTION_VALUE_MAX_BYTES;
  }
  return options;
}

static void log_lua_object_registry_check(
  const char *source,
  const char *name,
  const char *path,
  const char *class_name,
  uintptr_t address
) {
  int path_hit = 0;
  int name_hit = 0;
  int class_hit = 0;
  int address_hit = 0;
  for (size_t i = 0; i < ue_candidate_object_handle_count; ++i) {
    const LuaObjectHandle *object = &ue_candidate_object_handles[i];
    if (path && path[0] && str_equal(object->path, path)) {
      path_hit = 1;
    }
    if (name && name[0] && str_equal(object->name, name)) {
      name_hit = 1;
    }
    if (class_name && class_name[0] && str_equal(object->class_name, class_name)) {
      class_hit = 1;
    }
    if (address && object->address == address) {
      address_hit = 1;
    }
  }
  static Line line;
  line_init(&line);
  line_append(&line, "event=lua-object-registry-check source=");
  line_append(&line, source);
  line_append(&line, " status=");
  line_append(&line, (path_hit && name_hit && class_hit && address_hit) ? "passed" : "failed");
  line_append(&line, " name=");
  line_append(&line, name && name[0] ? name : "");
  line_append(&line, " path=");
  line_append(&line, path && path[0] ? path : "");
  line_append(&line, " class=");
  line_append(&line, class_name && class_name[0] ? class_name : "");
  line_append(&line, " address=");
  line_append_hex(&line, address);
  line_append(&line, " pathHit=");
  line_append(&line, path_hit ? "true" : "false");
  line_append(&line, " nameHit=");
  line_append(&line, name_hit ? "true" : "false");
  line_append(&line, " classHit=");
  line_append(&line, class_hit ? "true" : "false");
  line_append(&line, " addressHit=");
  line_append(&line, address_hit ? "true" : "false");
  line_append(&line, " registryCount=");
  line_append_dec(&line, ue_candidate_object_handle_count);
  line_append(&line, " registryProvenance=");
  line_append(&line, registry_value_provenance(name, path, class_name));
  emit_line(&line);
}

static int register_lua_object_candidate(const char *source, const char *safe_name, const char *class_name, uintptr_t target) {
  static char object_path[MAX_LUA_OBJECT_PATH];
  copy_string(object_path, sizeof(object_path), "/RuntimeProbe/");
  size_t prefix_len = cstr_len(object_path);
  size_t name_len = cstr_len(safe_name);
  for (size_t i = 0; i < name_len && prefix_len + i + 1 < sizeof(object_path); ++i) {
    object_path[prefix_len + i] = safe_name[i];
    object_path[prefix_len + i + 1] = '\0';
  }
  int registered_candidate = add_ue_candidate_object_handle(object_path, safe_name, class_name, target);
  static Line line;
  line_init(&line);
  line_append(&line, "event=lua-object-registry source=");
  line_append(&line, source);
  line_append(&line, " status=");
  line_append(&line, registered_candidate ? "added" : "skipped");
  line_append(&line, " name=");
  line_append(&line, safe_name);
  line_append(&line, " path=");
  line_append(&line, object_path);
  line_append(&line, " class=");
  line_append(&line, class_name);
  line_append(&line, " address=");
  line_append_hex(&line, target);
  line_append(&line, " registryCount=");
  line_append_dec(&line, ue_candidate_object_handle_count);
  line_append(&line, " registryProvenance=");
  line_append(&line, registry_value_provenance(safe_name, object_path, class_name));
  emit_line(&line);
  log_lua_object_registry_check(source, safe_name, object_path, class_name, target);
  return registered_candidate;
}

static const char *ue_uobject_anchor_class_name(const char *safe_name, const char *decoded_class_name) {
  if (decoded_class_name && decoded_class_name[0]) {
    return decoded_class_name;
  }
  if (safe_name && str_equal(safe_name, "GWorld")) {
    return "UWorld";
  }
  if (safe_name && str_equal(safe_name, "GEngine")) {
    return "UEngine";
  }
  return "UObjectCandidate";
}

static int is_fname_pool_anchor_name(const char *name) {
  return contains_ci(name, "FNamePool") ||
         contains_ci(name, "GName") ||
         contains_ci(name, "NamePool") ||
         contains_ci(name, "SelfTestFNamePool");
}

static int ue_fname_allow_missing_none(void) {
  return env_bool("DUNE_WIN_CLIENT_PROBE_UE_FNAME_ALLOW_MISSING_NONE", 0);
}

static int ue_object_array_class_reflection_probe_enabled(void) {
  return env_bool("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_CLASS_REFLECTION_PROBE", 0);
}

static size_t ue_object_array_class_reflection_max(void) {
  int value = env_int("DUNE_WIN_CLIENT_PROBE_UE_OBJECT_ARRAY_CLASS_REFLECTION_MAX", 32);
  return value > 0 ? (size_t)value : 0U;
}

static int ue_process_event_vtable_scan_enabled(void) {
  return env_bool("DUNE_WIN_CLIENT_PROBE_UE_PROCESS_EVENT_VTABLE_SCAN", 0);
}

static size_t ue_process_event_vtable_scan_slots(void) {
  int value = env_int("DUNE_WIN_CLIENT_PROBE_UE_PROCESS_EVENT_VTABLE_SCAN_SLOTS", 96);
  if (value <= 0) {
    return 0U;
  }
  if (value > 512) {
    return 512U;
  }
  return (size_t)value;
}

static size_t ue_process_event_vtable_scan_max_objects(void) {
  int value = env_int("DUNE_WIN_CLIENT_PROBE_UE_PROCESS_EVENT_VTABLE_SCAN_MAX_OBJECTS", 0);
  return value > 0 ? (size_t)value : 0U;
}

typedef struct {
  uintptr_t first_block;
  size_t plausible_entries;
  uintptr_t first_entry;
  uint16_t first_header;
  size_t first_length;
  int first_wide;
  int first_block_entry_plausible;
  uint16_t first_block_header;
  size_t first_block_length;
  int first_block_wide;
  uint32_t current_block;
  uint32_t current_byte_cursor;
  int allocator_state_plausible;
  int first_block_entry_none;
} UeFNameCandidateMetrics;

static int fname_pool_candidate_metrics(
  uintptr_t pool,
  const UeFNameOptions *options,
  UeFNameCandidateMetrics *metrics
) {
  if (metrics) {
    zero_bytes(metrics, sizeof(*metrics));
  }
  MEMORY_BASIC_INFORMATION_WIN64 mbi;
  SIZE_T got = VirtualQuery((const void *)(pool + options->blocks_offset), &mbi, sizeof(mbi));
  uintptr_t first_block = 0;
  if (!got || mbi.State != MEM_COMMIT ||
      !read_pointer_at(&mbi, pool + options->blocks_offset, &first_block) || first_block == 0) {
    return 0;
  }
  uint32_t current_block = 0;
  uint32_t current_byte_cursor = 0;
  if (!read_u32_at(&mbi, pool + 0x8, &current_block) ||
      !read_u32_at(&mbi, pool + 0xc, &current_byte_cursor)) {
    return 0;
  }
  int allocator_state_plausible = current_block < 8192U && current_byte_cursor < (2U * 1024U * 1024U);
  if (!allocator_state_plausible) {
    return 0;
  }
  MEMORY_BASIC_INFORMATION_WIN64 block_mbi;
  SIZE_T block_got = VirtualQuery((const void *)first_block, &block_mbi, sizeof(block_mbi));
  if (!block_got || block_mbi.State != MEM_COMMIT ||
      !readable_protect(block_mbi.Protect) || executable_protect(block_mbi.Protect)) {
    return 0;
  }
  if (metrics) {
    metrics->first_block = first_block;
    metrics->current_block = current_block;
    metrics->current_byte_cursor = current_byte_cursor;
    metrics->allocator_state_plausible = allocator_state_plausible;
  }
  if (pool == (uintptr_t)&ue_self_test_fname_pool) {
    if (metrics) {
      metrics->plausible_entries = 1;
      metrics->first_block_entry_plausible = 1;
    }
    return 1;
  }
  size_t plausible_entries = 0;
  size_t scan_limit = 4096;
  if (options->stride == 0) {
    return 0;
  }
  for (size_t offset = 0; offset + sizeof(uint16_t) < scan_limit; offset += options->stride) {
    uintptr_t entry = first_block + offset;
    uint16_t header = 0;
    if (!region_contains_range(&block_mbi, entry, sizeof(header)) || !read_u16_at(&block_mbi, entry, &header)) {
      break;
    }
    int candidate_wide[2] = {(header & 1U) ? 1 : 0, (header & 1U) ? 1 : 0};
    size_t candidate_length[2] = {(size_t)(header >> 1), (size_t)(header >> 6)};
    int matched_wide = 0;
    size_t matched_length = 0;
    int matched = 0;
    for (size_t mode = 0; mode < 2 && !matched; ++mode) {
      int is_wide = candidate_wide[mode];
      size_t length = candidate_length[mode];
      if (length == 0 || length > options->max_length) {
        continue;
      }
      size_t bytes = is_wide ? length * sizeof(uint16_t) : length;
      if (!region_contains_range(&block_mbi, entry + sizeof(header), bytes)) {
        continue;
      }
      size_t printable = 0;
      size_t alpha = 0;
      for (size_t i = 0; i < length; ++i) {
        unsigned int ch = 0;
        if (is_wide) {
          const unsigned char *source = (const unsigned char *)(entry + sizeof(header) + i * sizeof(uint16_t));
          ch = (unsigned int)source[0] | ((unsigned int)source[1] << 8);
        } else {
          ch = *(const unsigned char *)(entry + sizeof(header) + i);
        }
        if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
            (ch >= '0' && ch <= '9') || ch == '_' || ch == '-' ||
            ch == '.' || ch == '/' || ch == ':') {
          ++printable;
          if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')) {
            ++alpha;
          }
        }
      }
      if (printable == length && alpha > 0) {
        matched = 1;
        matched_wide = is_wide;
        matched_length = length;
      }
    }
    if (offset == 0 && metrics) {
      metrics->first_block_header = header;
      metrics->first_block_length = matched_length ? matched_length : (size_t)(header >> 1);
      metrics->first_block_wide = matched_wide;
    }
    if (matched) {
      ++plausible_entries;
      if (metrics && metrics->plausible_entries == 0) {
        metrics->first_entry = entry;
        metrics->first_header = header;
        metrics->first_length = matched_length;
        metrics->first_wide = matched_wide;
      }
      if (metrics) {
        metrics->plausible_entries = plausible_entries;
        if (offset == 0) {
          metrics->first_block_entry_plausible = 1;
          if (!matched_wide && matched_length == 4 &&
              *(const unsigned char *)(entry + sizeof(header) + 0) == 'N' &&
              *(const unsigned char *)(entry + sizeof(header) + 1) == 'o' &&
              *(const unsigned char *)(entry + sizeof(header) + 2) == 'n' &&
              *(const unsigned char *)(entry + sizeof(header) + 3) == 'e') {
            metrics->first_block_entry_none = 1;
          }
        }
      }
    }
  }
  int strict_gate = metrics ?
    (metrics->allocator_state_plausible && metrics->first_block_entry_none && metrics->plausible_entries >= 4) :
    (plausible_entries >= 4);
  int relaxed_gate = metrics ?
    (ue_fname_allow_missing_none() && metrics->allocator_state_plausible &&
     metrics->first_block_entry_plausible && metrics->plausible_entries >= 32) :
    (ue_fname_allow_missing_none() && plausible_entries >= 32);
  return strict_gate || relaxed_gate;
}

static int fname_pool_candidate_readable_with_block(
  uintptr_t pool,
  const UeFNameOptions *options,
  uintptr_t *first_block_out
) {
  UeFNameCandidateMetrics metrics;
  if (!fname_pool_candidate_metrics(pool, options, &metrics)) {
    return 0;
  }
  if (first_block_out) {
    *first_block_out = metrics.first_block;
  }
  return 1;
}

static int fname_pool_candidate_readable(uintptr_t pool, const UeFNameOptions *options) {
  return fname_pool_candidate_readable_with_block(pool, options, NULL);
}

static int add_runtime_discovered_anchor(
  UeAnchor *anchors,
  size_t *anchor_count,
  const char *name,
  uintptr_t address
) {
  static Line line;
  if (!anchors || !anchor_count || !name || !name[0] || address == 0 || *anchor_count >= MAX_UE_ANCHORS) {
    return 0;
  }
  if (ue_anchor_name_exists(anchors, *anchor_count, name)) {
    line_init(&line);
    line_append(&line, "event=ue-runtime-anchor name=");
    line_append(&line, name);
    line_append(&line, " status=duplicate addr=");
    line_append_hex(&line, address);
    emit_line(&line);
    return 0;
  }
  if (!address_is_target_image(address)) {
    line_init(&line);
    line_append(&line, "event=ue-runtime-anchor name=");
    line_append(&line, name);
    line_append(&line, " status=not-target-image addr=");
    line_append_hex(&line, address);
    emit_line(&line);
    return 0;
  }
  MEMORY_BASIC_INFORMATION_WIN64 mbi;
  SIZE_T got = VirtualQuery((const void *)address, &mbi, sizeof(mbi));
  static char module_path[1024];
  static char safe_module[1024];
  module_path[0] = '\0';
  safe_module[0] = '\0';
  if (got) {
    GetModuleFileNameA((HMODULE)mbi.AllocationBase, module_path, sizeof(module_path));
    safe_value(module_path, safe_module, sizeof(safe_module));
  }
  copy_string(anchors[*anchor_count].name, sizeof(anchors[*anchor_count].name), name);
  anchors[*anchor_count].address = address;
  ++(*anchor_count);
  line_init(&line);
  line_append(&line, "event=ue-runtime-anchor name=");
  line_append(&line, name);
  line_append(&line, " group=");
  line_append(&line, ue_anchor_group_for_name(name));
  line_append(&line, " status=promoted addr=");
  line_append_hex(&line, address);
  line_append(&line, " rva=");
  line_append_hex(&line, (got && (uintptr_t)mbi.AllocationBase) ? address - (uintptr_t)mbi.AllocationBase : 0);
  line_append(&line, " allocationBase=");
  line_append_hex(&line, got ? (uintptr_t)mbi.AllocationBase : 0);
  line_append(&line, " protect=");
  line_append_hex(&line, got ? mbi.Protect : 0);
  line_append(&line, " module=");
  line_append(&line, safe_module);
  emit_line(&line);
  return 1;
}

static void format_runtime_candidate_name(char *out, size_t out_size, const char *prefix, size_t index) {
  if (!out || out_size == 0) {
    return;
  }
  size_t written = 0;
  if (prefix) {
    while (prefix[written] && written + 1 < out_size) {
      out[written] = prefix[written];
      ++written;
    }
  }
  char digits[32];
  size_t digit_count = 0;
  unsigned long value = (unsigned long)index;
  do {
    digits[digit_count++] = (char)('0' + (value % 10UL));
    value /= 10UL;
  } while (value && digit_count < sizeof(digits));
  while (digit_count > 0 && written + 1 < out_size) {
    out[written++] = digits[--digit_count];
  }
  out[written] = '\0';
}

static int ue_object_array_header_plausible(
  uintptr_t base,
  const UeObjectArrayOptions *options,
  uint32_t *num_elements_out,
  uint32_t *num_chunks_out
) {
  MEMORY_BASIC_INFORMATION_WIN64 base_mbi;
  SIZE_T base_got = VirtualQuery((const void *)base, &base_mbi, sizeof(base_mbi));
  if (!base_got || base_mbi.State != MEM_COMMIT || !readable_protect(base_mbi.Protect)) {
    return 0;
  }
  uintptr_t chunks = 0;
  uint32_t max_elements = 0;
  uint32_t num_elements = 0;
  uint32_t max_chunks = 0;
  uint32_t num_chunks = 0;
  if (!read_pointer_at(&base_mbi, base + 0x0, &chunks) ||
      !read_u32_at(&base_mbi, base + 0x10, &max_elements) ||
      !read_u32_at(&base_mbi, base + 0x14, &num_elements) ||
      !read_u32_at(&base_mbi, base + 0x18, &max_chunks) ||
      !read_u32_at(&base_mbi, base + 0x1c, &num_chunks)) {
    return 0;
  }
  if (chunks == 0 || num_elements == 0 || num_chunks == 0 ||
      max_elements < num_elements || max_chunks < num_chunks ||
      max_elements > 100000000U ||
      max_chunks > 1048576U || num_chunks > 1048576U ||
      num_elements > options->max_objects * 4096U) {
    return 0;
  }
  MEMORY_BASIC_INFORMATION_WIN64 chunks_mbi;
  SIZE_T chunks_got = VirtualQuery((const void *)chunks, &chunks_mbi, sizeof(chunks_mbi));
  uintptr_t first_chunk = 0;
  if (!chunks_got || chunks_mbi.State != MEM_COMMIT ||
      !read_pointer_at(&chunks_mbi, chunks, &first_chunk) || first_chunk == 0) {
    return 0;
  }
  MEMORY_BASIC_INFORMATION_WIN64 first_chunk_mbi;
  SIZE_T first_chunk_got = VirtualQuery((const void *)first_chunk, &first_chunk_mbi, sizeof(first_chunk_mbi));
  if (!first_chunk_got || first_chunk_mbi.State != MEM_COMMIT ||
      !readable_protect(first_chunk_mbi.Protect) || executable_protect(first_chunk_mbi.Protect)) {
    return 0;
  }
  if (num_elements_out) {
    *num_elements_out = num_elements;
  }
  if (num_chunks_out) {
    *num_chunks_out = num_chunks;
  }
  return 1;
}

static size_t collect_ue_runtime_discovered_anchors(
  UeAnchor *anchors,
  size_t anchor_count,
  const UeFNameOptions *fname_options,
  const UeObjectArrayOptions *object_array_options,
  const char *phase
) {
  if (!env_bool("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_ROOTS", 0)) {
    return anchor_count;
  }
  size_t max_region_bytes = env_size("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_MAX_REGION_BYTES", DEFAULT_MAX_REGION_BYTES);
  size_t max_candidates = env_size("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_MAX_CANDIDATES", 8);
  size_t min_object_array_elements = env_size("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_MIN_OBJECT_ARRAY_ELEMENTS", 1);
  if (max_candidates == 0 || max_candidates > 64) {
    max_candidates = 8;
  }
  if (min_object_array_elements == 0 || min_object_array_elements > 1000000) {
    min_object_array_elements = 1;
  }
  static Line line;
  line_init(&line);
  line_append(&line, "event=ue-runtime-discovery-start phase=");
  line_append(&line, phase);
  line_append(&line, " maxRegionBytes=");
  line_append_dec(&line, max_region_bytes);
  line_append(&line, " maxCandidates=");
  line_append_dec(&line, max_candidates);
  line_append(&line, " minObjectArrayElements=");
  line_append_dec(&line, min_object_array_elements);
  line_append(&line, " includePrivateRw=");
  line_append(&line, env_bool("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_INCLUDE_PRIVATE_RW", 0) ? "true" : "false");
  line_append(&line, " maxRejectedFNameSamples=");
  line_append_dec(&line, env_size("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_MAX_REJECTED_FNAME_SAMPLES", 0));
  emit_line(&line);

  uintptr_t first_fname_pool = 0;
  uintptr_t first_object_array = 0;
  uintptr_t fname_pool_candidates[64];
  uintptr_t object_array_candidates[64];
  size_t fname_hits = 0;
  size_t object_array_hits = 0;
  size_t oversized_regions = 0;
  size_t target_writable_regions = 0;
  size_t private_writable_regions = 0;
  size_t scanned_slots = 0;
  size_t fname_probes = 0;
  size_t object_array_probes = 0;
  int include_private_rw = env_bool("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_INCLUDE_PRIVATE_RW", 0);
  int promote_ambiguous_roots = env_bool("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_PROMOTE_AMBIGUOUS_ROOTS", 0);
  size_t max_rejected_fname_samples = env_size("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_MAX_REJECTED_FNAME_SAMPLES", 0);
  size_t rejected_fname_samples = 0;
  int discovery_limited = 0;
  uintptr_t cursor = 0x10000;
  while ((fname_hits <= max_candidates || object_array_hits <= max_candidates) && cursor < (uintptr_t)-0x10000) {
    MEMORY_BASIC_INFORMATION_WIN64 mbi;
    SIZE_T got = VirtualQuery((const void *)cursor, &mbi, sizeof(mbi));
    if (!got || mbi.RegionSize == 0) {
      cursor += 0x10000;
      continue;
    }
    uintptr_t base = (uintptr_t)mbi.BaseAddress;
    uintptr_t next = base + (uintptr_t)mbi.RegionSize;
    if (next <= cursor) {
      break;
    }
    int target_image_region = mbi.Type == MEM_IMAGE && address_is_target_image(base);
    int private_rw_region = include_private_rw && mbi.Type == MEM_PRIVATE;
    if (mbi.State != MEM_COMMIT ||
        !readable_protect(mbi.Protect) || !writable_protect(mbi.Protect) ||
        (!target_image_region && !private_rw_region)) {
      cursor = next;
      continue;
    }
    static char module_path[1024];
    static char safe_module_path[1024];
    module_path[0] = '\0';
    safe_module_path[0] = '\0';
    GetModuleFileNameA((HMODULE)mbi.AllocationBase, module_path, sizeof(module_path));
    safe_value(module_path, safe_module_path, sizeof(safe_module_path));
    ++target_writable_regions;
    if (private_rw_region) {
      ++private_writable_regions;
    }
    if ((size_t)mbi.RegionSize > max_region_bytes) {
      ++oversized_regions;
      cursor = next;
      continue;
    }
    uintptr_t start = (base + sizeof(uintptr_t) - 1U) & ~(uintptr_t)(sizeof(uintptr_t) - 1U);
    for (uintptr_t slot = start; slot + sizeof(uintptr_t) <= next; slot += sizeof(uintptr_t)) {
      ++scanned_slots;
      if (fname_hits <= max_candidates && slot >= fname_options->blocks_offset) {
        uintptr_t pool = slot - fname_options->blocks_offset;
        UeFNameCandidateMetrics fname_metrics;
        ++fname_probes;
        int fname_candidate_ok = fname_pool_candidate_metrics(pool, fname_options, &fname_metrics);
        if (fname_candidate_ok) {
          int first_block_same_region = region_contains_range(&mbi, fname_metrics.first_block, 1);
          int first_block_target_image = address_is_target_image(fname_metrics.first_block);
          ++fname_hits;
          if (fname_hits <= max_candidates && fname_hits <= (sizeof(fname_pool_candidates) / sizeof(fname_pool_candidates[0]))) {
            fname_pool_candidates[fname_hits - 1] = pool;
          }
          if (fname_hits == 1) {
            first_fname_pool = pool;
          }
          line_init(&line);
          line_append(&line, "event=ue-runtime-discovery-candidate name=RuntimeFNamePool addr=");
          line_append_hex(&line, pool);
          line_append(&line, " blockSlot=");
          line_append_hex(&line, slot);
          line_append(&line, " firstBlock=");
          line_append_hex(&line, fname_metrics.first_block);
          line_append(&line, " blocksOffset=");
          line_append_hex(&line, fname_options->blocks_offset);
          line_append(&line, " stride=");
          line_append_dec(&line, fname_options->stride);
          line_append(&line, " hit=");
          line_append_dec(&line, fname_hits);
          line_append(&line, " plausibleEntries=");
          line_append_dec(&line, fname_metrics.plausible_entries);
          line_append(&line, " firstEntry=");
          line_append_hex(&line, fname_metrics.first_entry);
          line_append(&line, " firstHeader=");
          line_append_hex(&line, fname_metrics.first_header);
          line_append(&line, " firstLength=");
          line_append_dec(&line, fname_metrics.first_length);
          line_append(&line, " firstWide=");
          line_append(&line, fname_metrics.first_wide ? "true" : "false");
          line_append(&line, " firstBlockEntryPlausible=");
          line_append(&line, fname_metrics.first_block_entry_plausible ? "true" : "false");
          line_append(&line, " firstBlockEntryNone=");
          line_append(&line, fname_metrics.first_block_entry_none ? "true" : "false");
          line_append(&line, " firstBlockHeader=");
          line_append_hex(&line, fname_metrics.first_block_header);
          line_append(&line, " firstBlockLength=");
          line_append_dec(&line, fname_metrics.first_block_length);
          line_append(&line, " firstBlockWide=");
          line_append(&line, fname_metrics.first_block_wide ? "true" : "false");
          line_append(&line, " currentBlock=");
          line_append_dec(&line, fname_metrics.current_block);
          line_append(&line, " currentByteCursor=");
          line_append_dec(&line, fname_metrics.current_byte_cursor);
          line_append(&line, " allocatorStatePlausible=");
          line_append(&line, fname_metrics.allocator_state_plausible ? "true" : "false");
          line_append(&line, " targetImage=");
          line_append(&line, target_image_region ? "true" : "false");
          line_append(&line, " firstBlockSameRegion=");
          line_append(&line, first_block_same_region ? "true" : "false");
          line_append(&line, " firstBlockTargetImage=");
          line_append(&line, first_block_target_image ? "true" : "false");
          line_append(&line, " rva=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase ? pool - (uintptr_t)mbi.AllocationBase : 0);
          line_append(&line, " allocationBase=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase);
          line_append(&line, " regionBase=");
          line_append_hex(&line, base);
          line_append(&line, " protect=");
          line_append_hex(&line, mbi.Protect);
          line_append(&line, " module=");
          line_append(&line, safe_module_path);
          emit_line(&line);
        } else if (rejected_fname_samples < max_rejected_fname_samples &&
                   fname_metrics.first_block != 0 &&
                   fname_metrics.allocator_state_plausible &&
                   fname_metrics.first_block_entry_plausible &&
                   fname_metrics.plausible_entries >= 4) {
          int first_block_same_region = region_contains_range(&mbi, fname_metrics.first_block, 1);
          int first_block_target_image = address_is_target_image(fname_metrics.first_block);
          ++rejected_fname_samples;
          line_init(&line);
          line_append(&line, "event=ue-runtime-discovery-rejected name=RuntimeFNamePool reason=");
          line_append(&line, fname_metrics.first_block_entry_none ? "strict-gate" : "missing-none-entry");
          line_append(&line, " addr=");
          line_append_hex(&line, pool);
          line_append(&line, " blockSlot=");
          line_append_hex(&line, slot);
          line_append(&line, " firstBlock=");
          line_append_hex(&line, fname_metrics.first_block);
          line_append(&line, " sample=");
          line_append_dec(&line, rejected_fname_samples);
          line_append(&line, " plausibleEntries=");
          line_append_dec(&line, fname_metrics.plausible_entries);
          line_append(&line, " firstEntry=");
          line_append_hex(&line, fname_metrics.first_entry);
          line_append(&line, " firstHeader=");
          line_append_hex(&line, fname_metrics.first_header);
          line_append(&line, " firstLength=");
          line_append_dec(&line, fname_metrics.first_length);
          line_append(&line, " firstWide=");
          line_append(&line, fname_metrics.first_wide ? "true" : "false");
          line_append(&line, " firstBlockEntryPlausible=");
          line_append(&line, fname_metrics.first_block_entry_plausible ? "true" : "false");
          line_append(&line, " firstBlockEntryNone=");
          line_append(&line, fname_metrics.first_block_entry_none ? "true" : "false");
          line_append(&line, " firstBlockHeader=");
          line_append_hex(&line, fname_metrics.first_block_header);
          line_append(&line, " firstBlockLength=");
          line_append_dec(&line, fname_metrics.first_block_length);
          line_append(&line, " firstBlockWide=");
          line_append(&line, fname_metrics.first_block_wide ? "true" : "false");
          line_append(&line, " currentBlock=");
          line_append_dec(&line, fname_metrics.current_block);
          line_append(&line, " currentByteCursor=");
          line_append_dec(&line, fname_metrics.current_byte_cursor);
          line_append(&line, " allocatorStatePlausible=");
          line_append(&line, fname_metrics.allocator_state_plausible ? "true" : "false");
          line_append(&line, " targetImage=");
          line_append(&line, target_image_region ? "true" : "false");
          line_append(&line, " firstBlockSameRegion=");
          line_append(&line, first_block_same_region ? "true" : "false");
          line_append(&line, " firstBlockTargetImage=");
          line_append(&line, first_block_target_image ? "true" : "false");
          line_append(&line, " rva=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase ? pool - (uintptr_t)mbi.AllocationBase : 0);
          line_append(&line, " allocationBase=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase);
          line_append(&line, " regionBase=");
          line_append_hex(&line, base);
          line_append(&line, " protect=");
          line_append_hex(&line, mbi.Protect);
          line_append(&line, " module=");
          line_append(&line, safe_module_path);
          emit_line(&line);
        }
      }
      if (object_array_hits <= max_candidates) {
        uintptr_t object_base = slot + object_array_options->array_offset;
        uint32_t num_elements = 0;
        uint32_t num_chunks = 0;
        ++object_array_probes;
        if (ue_object_array_header_plausible(object_base, object_array_options, &num_elements, &num_chunks) &&
            num_elements >= min_object_array_elements) {
          uintptr_t chunks = 0;
          uintptr_t first_chunk = 0;
          int chunks_readable = 0;
          int first_chunk_readable = 0;
          int first_object_readable = 0;
          if (read_pointer_at(&mbi, object_base, &chunks) && chunks != 0) {
            MEMORY_BASIC_INFORMATION_WIN64 chunks_mbi;
            SIZE_T chunks_got = VirtualQuery((const void *)chunks, &chunks_mbi, sizeof(chunks_mbi));
            chunks_readable = chunks_got && chunks_mbi.State == MEM_COMMIT && readable_protect(chunks_mbi.Protect);
            if (chunks_readable && read_pointer_at(&chunks_mbi, chunks, &first_chunk) && first_chunk != 0) {
              MEMORY_BASIC_INFORMATION_WIN64 first_chunk_mbi;
              SIZE_T first_chunk_got = VirtualQuery((const void *)first_chunk, &first_chunk_mbi, sizeof(first_chunk_mbi));
              first_chunk_readable = first_chunk_got && first_chunk_mbi.State == MEM_COMMIT && readable_protect(first_chunk_mbi.Protect);
              if (first_chunk_readable) {
                uintptr_t first_object = 0;
                first_object_readable = read_pointer_at(&first_chunk_mbi, first_chunk + object_array_options->object_offset, &first_object) && first_object != 0;
              }
            }
          }
          ++object_array_hits;
          if (object_array_hits <= max_candidates && object_array_hits <= (sizeof(object_array_candidates) / sizeof(object_array_candidates[0]))) {
            object_array_candidates[object_array_hits - 1] = slot;
          }
          if (object_array_hits == 1) {
            first_object_array = slot;
          }
          line_init(&line);
          line_append(&line, "event=ue-runtime-discovery-candidate name=RuntimeGUObjectArray addr=");
          line_append_hex(&line, slot);
          line_append(&line, " base=");
          line_append_hex(&line, object_base);
          line_append(&line, " chunks=");
          line_append_hex(&line, chunks);
          line_append(&line, " firstChunk=");
          line_append_hex(&line, first_chunk);
          line_append(&line, " numElements=");
          line_append_dec(&line, num_elements);
          line_append(&line, " numChunks=");
          line_append_dec(&line, num_chunks);
          line_append(&line, " hit=");
          line_append_dec(&line, object_array_hits);
          line_append(&line, " targetImage=");
          line_append(&line, target_image_region ? "true" : "false");
          line_append(&line, " chunksReadable=");
          line_append(&line, chunks_readable ? "true" : "false");
          line_append(&line, " firstChunkReadable=");
          line_append(&line, first_chunk_readable ? "true" : "false");
          line_append(&line, " firstObjectReadable=");
          line_append(&line, first_object_readable ? "true" : "false");
          line_append(&line, " rva=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase ? slot - (uintptr_t)mbi.AllocationBase : 0);
          line_append(&line, " allocationBase=");
          line_append_hex(&line, (uintptr_t)mbi.AllocationBase);
          line_append(&line, " regionBase=");
          line_append_hex(&line, base);
          line_append(&line, " protect=");
          line_append_hex(&line, mbi.Protect);
          line_append(&line, " module=");
          line_append(&line, safe_module_path);
          emit_line(&line);
        }
      }
      if (fname_hits > 0 && object_array_hits > max_candidates) {
        discovery_limited = 1;
        break;
      }
    }
    if (discovery_limited) {
      break;
    }
    cursor = next;
  }

  if (discovery_limited) {
    line_init(&line);
    line_append(&line, "event=ue-runtime-discovery-limited phase=");
    line_append(&line, phase);
    line_append(&line, " reason=object-array-ambiguous-with-fname-hit fnameHits=");
    line_append_dec(&line, fname_hits);
    line_append(&line, " objectArrayHits=");
    line_append_dec(&line, object_array_hits);
    line_append(&line, " maxCandidates=");
    line_append_dec(&line, max_candidates);
    emit_line(&line);
  }
  if (target_writable_regions == 0) {
    line_init(&line);
    line_append(&line, "event=ue-runtime-discovery name=target-writable-image-regions status=missing phase=");
    line_append(&line, phase);
    emit_line(&line);
  }
  if (fname_hits == 1) {
    add_runtime_discovered_anchor(anchors, &anchor_count, "RuntimeFNamePool", first_fname_pool);
  } else if (promote_ambiguous_roots && fname_hits > 1 && fname_hits <= max_candidates) {
    for (size_t i = 0; i < fname_hits && i < (sizeof(fname_pool_candidates) / sizeof(fname_pool_candidates[0])); ++i) {
      char candidate_name[64];
      format_runtime_candidate_name(candidate_name, sizeof(candidate_name), "RuntimeFNamePoolCandidate", i + 1);
      add_runtime_discovered_anchor(anchors, &anchor_count, candidate_name, fname_pool_candidates[i]);
    }
  } else {
    line_init(&line);
    line_append(&line, "event=ue-runtime-discovery name=RuntimeFNamePool status=");
    line_append(&line, fname_hits == 0 ? "missing" : "ambiguous");
    line_append(&line, " hits=");
    line_append_dec(&line, fname_hits);
    emit_line(&line);
  }
  if (object_array_hits == 1) {
    add_runtime_discovered_anchor(anchors, &anchor_count, "RuntimeGUObjectArray", first_object_array);
  } else if (promote_ambiguous_roots && object_array_hits > 1 && object_array_hits <= max_candidates) {
    for (size_t i = 0; i < object_array_hits && i < (sizeof(object_array_candidates) / sizeof(object_array_candidates[0])); ++i) {
      char candidate_name[64];
      format_runtime_candidate_name(candidate_name, sizeof(candidate_name), "RuntimeGUObjectArrayCandidate", i + 1);
      add_runtime_discovered_anchor(anchors, &anchor_count, candidate_name, object_array_candidates[i]);
    }
  } else {
    line_init(&line);
    line_append(&line, "event=ue-runtime-discovery name=RuntimeGUObjectArray status=");
    line_append(&line, object_array_hits == 0 ? "missing" : "ambiguous");
    line_append(&line, " hits=");
    line_append_dec(&line, object_array_hits);
    emit_line(&line);
  }
  line_init(&line);
  line_append(&line, "event=ue-runtime-discovery-finish phase=");
  line_append(&line, phase);
  line_append(&line, " fnameHits=");
  line_append_dec(&line, fname_hits);
  line_append(&line, " objectArrayHits=");
  line_append_dec(&line, object_array_hits);
  line_append(&line, " targetWritableRegions=");
  line_append_dec(&line, target_writable_regions);
  line_append(&line, " privateWritableRegions=");
  line_append_dec(&line, private_writable_regions);
  line_append(&line, " oversizedRegions=");
  line_append_dec(&line, oversized_regions);
  line_append(&line, " scannedSlots=");
  line_append_dec(&line, scanned_slots);
  line_append(&line, " fnameProbes=");
  line_append_dec(&line, fname_probes);
  line_append(&line, " objectArrayProbes=");
  line_append_dec(&line, object_array_probes);
  line_append(&line, " rejectedFNameSamples=");
  line_append_dec(&line, rejected_fname_samples);
  line_append(&line, " limited=");
  line_append(&line, discovery_limited ? "true" : "false");
  line_append(&line, " anchors=");
  line_append_dec(&line, anchor_count);
  emit_line(&line);
  return anchor_count;
}

static size_t collect_ue_hook_target_anchors(UeAnchor *anchors, const char *phase, const char *event_name) {
  for (size_t i = 0; i < sizeof(UeAnchor) * MAX_UE_ANCHORS; ++i) {
    ((char *)anchors)[i] = 0;
  }
  size_t anchor_count = collect_ue_anchors(anchors);
  int signature_configured = ue_anchor_signatures_configured();
  static char candidate_globals[16384];
  int candidate_globals_configured =
    env_get("DUNE_WIN_CLIENT_PROBE_UE_CANDIDATE_GLOBALS", candidate_globals, sizeof(candidate_globals)) > 0;
  int auto_discover_configured = env_bool("DUNE_WIN_CLIENT_PROBE_UE_AUTO_DISCOVER_ROOTS", 0);
  if (signature_configured) {
    anchor_count = collect_ue_anchor_signature_anchors(anchors, anchor_count, phase);
  }
  if (candidate_globals_configured) {
    anchor_count = collect_ue_candidate_global_anchors(anchors, anchor_count);
  }
  if (auto_discover_configured) {
    UeFNameOptions fname_options = ue_fname_options();
    UeObjectArrayOptions object_array_options = ue_object_array_options();
    anchor_count = collect_ue_runtime_discovered_anchors(
      anchors,
      anchor_count,
      &fname_options,
      &object_array_options,
      phase
    );
  }
  if (anchor_count == 0 && (signature_configured || candidate_globals_configured || auto_discover_configured)) {
    static Line line;
    line_init(&line);
    line_append(&line, "event=");
    line_append(&line, event_name);
    line_append(&line, " phase=");
    line_append(&line, phase);
    line_append(&line, " status=no-resolved-hook-anchors");
    emit_line(&line);
  }
  return anchor_count;
}

static void copy_resolver_source(char *out, size_t out_size, const char *name, const char *mode) {
  static Line line;
  line_init(&line);
  line_append(&line, name);
  line_append_char(&line, ':');
  line_append(&line, mode);
  copy_string(out, out_size, line.text);
}

static void log_ue_fname_resolver_reject(
  const char *anchor_name,
  const char *mode,
  uintptr_t pool,
  const UeFNameOptions *options,
  const char *forced_reason
) {
  if (!env_bool("DUNE_WIN_CLIENT_PROBE_UE_FNAME_DIAGNOSTICS", 0)) {
    return;
  }
  UeFNameCandidateMetrics metrics;
  unsigned char *metric_bytes = (unsigned char *)&metrics;
  for (size_t i = 0; i < sizeof(metrics); ++i) {
    metric_bytes[i] = 0;
  }
  int ok = 0;
  if (!forced_reason) {
    ok = fname_pool_candidate_metrics(pool, options, &metrics);
  }
  const char *reason = forced_reason ? forced_reason : "strict-gate";
  if (!forced_reason && ok) {
    reason = "unexpected-readable";
  } else if (!forced_reason && metrics.first_block == 0) {
    reason = "first-block-unreadable-or-null";
  } else if (!forced_reason && !metrics.allocator_state_plausible) {
    reason = "allocator-state";
  } else if (!forced_reason && !metrics.first_block_entry_none) {
    reason = ue_fname_allow_missing_none() ? "missing-none-entry-relaxed-gate-failed" : "missing-none-entry";
  } else if (!forced_reason && metrics.plausible_entries < 4) {
    reason = "low-plausible-entries";
  }
  static Line line;
  line_init(&line);
  line_append(&line, "event=ue-fname-resolver-reject name=");
  line_append(&line, anchor_name ? anchor_name : "");
  line_append(&line, " mode=");
  line_append(&line, mode ? mode : "");
  line_append(&line, " reason=");
  line_append(&line, reason);
  line_append(&line, " pool=");
  line_append_hex(&line, pool);
  line_append(&line, " firstBlock=");
  line_append_hex(&line, metrics.first_block);
  line_append(&line, " plausibleEntries=");
  line_append_dec(&line, metrics.plausible_entries);
  line_append(&line, " firstEntry=");
  line_append_hex(&line, metrics.first_entry);
  line_append(&line, " firstHeader=");
  line_append_hex(&line, metrics.first_header);
  line_append(&line, " firstLength=");
  line_append_dec(&line, metrics.first_length);
  line_append(&line, " firstWide=");
  line_append(&line, metrics.first_wide ? "true" : "false");
  line_append(&line, " firstBlockEntryNone=");
  line_append(&line, metrics.first_block_entry_none ? "true" : "false");
  line_append(&line, " firstBlockHeader=");
  line_append_hex(&line, metrics.first_block_header);
  line_append(&line, " firstBlockLength=");
  line_append_dec(&line, metrics.first_block_length);
  line_append(&line, " firstBlockWide=");
  line_append(&line, metrics.first_block_wide ? "true" : "false");
  line_append(&line, " currentBlock=");
  line_append_dec(&line, metrics.current_block);
  line_append(&line, " currentByteCursor=");
  line_append_dec(&line, metrics.current_byte_cursor);
  line_append(&line, " allocatorStatePlausible=");
  line_append(&line, metrics.allocator_state_plausible ? "true" : "false");
  line_append(&line, " blocksOffset=");
  line_append_hex(&line, options->blocks_offset);
  line_append(&line, " stride=");
  line_append_dec(&line, options->stride);
  emit_line(&line);
}

static int find_ue_fname_resolver(
  const UeAnchor *anchors,
  size_t anchor_count,
  const UeFNameOptions *options,
  UeFNameResolver *resolver
) {
  unsigned char *bytes = (unsigned char *)resolver;
  for (size_t i = 0; i < sizeof(*resolver); ++i) {
    bytes[i] = 0;
  }
  if (options->pool_address) {
    uintptr_t pool = options->pool_address + options->pool_offset;
    if (fname_pool_candidate_readable(pool, options)) {
      resolver->pool = pool;
      resolver->available = 1;
      copy_string(resolver->source, sizeof(resolver->source), "env");
      return 1;
    }
    log_ue_fname_resolver_reject("env", "direct", pool, options, 0);
  }
  for (size_t i = 0; i < anchor_count; ++i) {
    if (!is_fname_pool_anchor_name(anchors[i].name)) {
      continue;
    }
    uintptr_t direct = anchors[i].address + options->pool_offset;
    if (fname_pool_candidate_readable(direct, options)) {
      resolver->pool = direct;
      resolver->available = 1;
      copy_resolver_source(resolver->source, sizeof(resolver->source), anchors[i].name, "direct");
      return 1;
    }
    log_ue_fname_resolver_reject(anchors[i].name, "direct", direct, options, 0);
    MEMORY_BASIC_INFORMATION_WIN64 anchor_mbi;
    SIZE_T anchor_got = VirtualQuery((const void *)anchors[i].address, &anchor_mbi, sizeof(anchor_mbi));
    uintptr_t indirect = 0;
    if (anchor_got && read_pointer_at(&anchor_mbi, anchors[i].address, &indirect) && indirect != 0) {
      uintptr_t pool = indirect + options->pool_offset;
      if (fname_pool_candidate_readable(pool, options)) {
        resolver->pool = pool;
        resolver->available = 1;
        copy_resolver_source(resolver->source, sizeof(resolver->source), anchors[i].name, "indirect");
        return 1;
      }
      log_ue_fname_resolver_reject(anchors[i].name, "indirect", pool, options, 0);
    } else {
      log_ue_fname_resolver_reject(anchors[i].name, "indirect", anchors[i].address, options, "anchor-pointer-unreadable");
    }
  }
  return 0;
}

static void cache_lua_fname_resolver(
  const UeFNameResolver *resolver,
  const UeFNameOptions *options
) {
  if (!resolver || !options || !resolver->available || resolver->pool == 0) {
    return;
  }
  const unsigned char *option_source = (const unsigned char *)options;
  unsigned char *option_dest = (unsigned char *)&active_lua_fname_options;
  for (size_t i = 0; i < sizeof(active_lua_fname_options); ++i) {
    option_dest[i] = option_source[i];
  }
  const unsigned char *resolver_source = (const unsigned char *)resolver;
  unsigned char *resolver_dest = (unsigned char *)&active_lua_fname_resolver;
  for (size_t i = 0; i < sizeof(active_lua_fname_resolver); ++i) {
    resolver_dest[i] = resolver_source[i];
  }
  active_lua_fname_resolver_available = 1;
}

static void copy_decoded_fname_char(char *out, size_t out_size, size_t *written, unsigned int ch) {
  if (*written + 1 >= out_size) {
    return;
  }
  if ((ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z') ||
      (ch >= '0' && ch <= '9') || ch == '_' || ch == '-' || ch == '.') {
    out[(*written)++] = (char)ch;
  } else if (ch >= 32 && ch < 127) {
    out[(*written)++] = '_';
  } else {
    out[(*written)++] = '?';
  }
  out[*written] = '\0';
}

static void append_uint_to_buffer(char *out, size_t out_size, size_t *written, unsigned int value) {
  char digits[16];
  size_t count = 0;
  if (value == 0) {
    copy_decoded_fname_char(out, out_size, written, '0');
    return;
  }
  while (value > 0 && count < sizeof(digits)) {
    digits[count++] = (char)('0' + (value % 10U));
    value /= 10U;
  }
  while (count > 0) {
    copy_decoded_fname_char(out, out_size, written, (unsigned int)digits[--count]);
  }
}

static int decode_ue_fname(
  const UeFNameResolver *resolver,
  const UeFNameOptions *options,
  uint32_t comparison_index,
  uint32_t number,
  char *decoded,
  size_t decoded_size,
  uintptr_t *entry_out,
  uint32_t *block_out,
  uint32_t *offset_out,
  int *wide_out,
  const char **status_out
) {
  if (decoded_size > 0) {
    decoded[0] = '\0';
  }
  if (entry_out) *entry_out = 0;
  if (block_out) *block_out = 0;
  if (offset_out) *offset_out = 0;
  if (wide_out) *wide_out = 0;
  if (status_out) *status_out = "unavailable";
  if (!resolver || !resolver->available || resolver->pool == 0) {
    return 0;
  }
  uint32_t block = comparison_index >> 16;
  uint32_t offset = comparison_index & 0xffffU;
  if (block_out) *block_out = block;
  if (offset_out) *offset_out = offset;
  uintptr_t block_slot = resolver->pool + options->blocks_offset + (uintptr_t)block * sizeof(uintptr_t);
  MEMORY_BASIC_INFORMATION_WIN64 slot_mbi;
  SIZE_T slot_got = VirtualQuery((const void *)block_slot, &slot_mbi, sizeof(slot_mbi));
  uintptr_t block_base = 0;
  if (!slot_got || !read_pointer_at(&slot_mbi, block_slot, &block_base) || block_base == 0) {
    if (status_out) *status_out = "block-unreadable";
    return 0;
  }
  uintptr_t entry = block_base + (uintptr_t)offset * options->stride;
  if (entry_out) *entry_out = entry;
  MEMORY_BASIC_INFORMATION_WIN64 entry_mbi;
  SIZE_T entry_got = VirtualQuery((const void *)entry, &entry_mbi, sizeof(entry_mbi));
  uint16_t header = 0;
  if (!entry_got || !read_u16_at(&entry_mbi, entry, &header)) {
    if (status_out) *status_out = "entry-unreadable";
    return 0;
  }
  int is_wide = (header & 1U) ? 1 : 0;
  size_t length = (size_t)(header >> 1);
  if (length == 0 || length > options->max_length) {
    length = (size_t)(header >> 6);
  }
  if (wide_out) *wide_out = is_wide;
  if (length == 0 || length > options->max_length) {
    if (status_out) *status_out = "length-invalid";
    return 0;
  }
  size_t bytes = is_wide ? length * sizeof(uint16_t) : length;
  if (!region_contains_range(&entry_mbi, entry + sizeof(uint16_t), bytes)) {
    if (status_out) *status_out = "name-truncated";
    return 0;
  }
  size_t written = 0;
  for (size_t i = 0; i < length; ++i) {
    unsigned int ch = 0;
    if (is_wide) {
      const unsigned char *source = (const unsigned char *)(entry + sizeof(uint16_t) + i * sizeof(uint16_t));
      ch = (unsigned int)source[0] | ((unsigned int)source[1] << 8);
    } else {
      ch = *(const unsigned char *)(entry + sizeof(uint16_t) + i);
    }
    copy_decoded_fname_char(decoded, decoded_size, &written, ch);
  }
  if (number > 0 && written + 2 < decoded_size) {
    copy_decoded_fname_char(decoded, decoded_size, &written, '_');
    append_uint_to_buffer(decoded, decoded_size, &written, number - 1);
  }
  if (status_out) *status_out = "decoded";
  return 1;
}

static void log_ue_fname_decode_diagnostic(
  const char *object_name,
  const char *source,
  uintptr_t object,
  const UeFNameResolver *resolver,
  const UeFNameOptions *options,
  uint32_t comparison_index,
  uint32_t number,
  uintptr_t entry,
  const char *status
) {
  static int diagnostic_count = 0;
  if (!env_bool("DUNE_WIN_CLIENT_PROBE_UE_FNAME_DIAGNOSTICS", 0)) {
    return;
  }
  int max_diagnostics = env_int("DUNE_WIN_CLIENT_PROBE_UE_FNAME_DIAGNOSTICS_MAX", 16);
  if (max_diagnostics <= 0 || diagnostic_count >= max_diagnostics) {
    return;
  }
  ++diagnostic_count;

  unsigned char raw[16];
  for (size_t i = 0; i < sizeof(raw); ++i) {
    raw[i] = 0;
  }
  size_t raw_size = 0;
  MEMORY_BASIC_INFORMATION_WIN64 entry_mbi;
  SIZE_T entry_got = entry ? VirtualQuery((const void *)entry, &entry_mbi, sizeof(entry_mbi)) : 0;
  if (entry_got && readable_protect(entry_mbi.Protect) && region_contains_range(&entry_mbi, entry, sizeof(raw))) {
    const unsigned char *source_bytes = (const unsigned char *)entry;
    for (size_t i = 0; i < sizeof(raw); ++i) {
      raw[i] = source_bytes[i];
    }
    raw_size = sizeof(raw);
  }

  uint16_t header = 0;
  if (raw_size >= sizeof(header)) {
    header = (uint16_t)raw[0] | (uint16_t)((uint16_t)raw[1] << 8);
  }

  static const char hex[] = "0123456789abcdef";
  static Line line;
  line_init(&line);
  line_append(&line, "event=ue-fname-diagnostic source=");
  line_append(&line, source);
  line_append(&line, " objectName=");
  line_append(&line, object_name);
  line_append(&line, " status=");
  line_append(&line, status ? status : "unknown");
  line_append(&line, " object=");
  line_append_hex(&line, object);
  line_append(&line, " pool=");
  line_append_hex(&line, resolver ? resolver->pool : 0);
  line_append(&line, " resolver=");
  line_append(&line, resolver ? resolver->source : "");
  line_append(&line, " comparisonIndex=");
  line_append_dec(&line, comparison_index);
  line_append(&line, " number=");
  line_append_dec(&line, number);
  line_append(&line, " entry=");
  line_append_hex(&line, entry);
  line_append(&line, " entryReadable=");
  line_append(&line, raw_size ? "true" : "false");
  line_append(&line, " raw=");
  for (size_t i = 0; i < raw_size; ++i) {
    line_append_char(&line, hex[(raw[i] >> 4) & 0xfU]);
    line_append_char(&line, hex[raw[i] & 0xfU]);
  }
  line_append(&line, " header=");
  line_append_hex(&line, header);
  line_append(&line, " lenShift1=");
  line_append_dec(&line, header >> 1);
  line_append(&line, " wideBit0=");
  line_append_dec(&line, header & 1U);
  line_append(&line, " lenShift6=");
  line_append_dec(&line, header >> 6);
  line_append(&line, " wideBit15=");
  line_append_dec(&line, (header >> 15) & 1U);
  line_append(&line, " blocksOffset=");
  line_append_hex(&line, options ? options->blocks_offset : 0);
  line_append(&line, " stride=");
  line_append_dec(&line, options ? options->stride : 0);
  emit_line(&line);
}

static void log_ue_fname_for_object(
  const char *object_name,
  const char *source,
  uintptr_t object,
  uint32_t comparison_index,
  uint32_t number,
  const UeFNameResolver *resolver,
  const UeFNameOptions *options
) {
  static Line line;
  if (!resolver || !resolver->available) {
    line_init(&line);
    line_append(&line, "event=ue-fname source=");
    line_append(&line, source);
    line_append(&line, " objectName=");
    line_append(&line, object_name);
    line_append(&line, " status=pool-unavailable object=");
    line_append_hex(&line, object);
    line_append(&line, " comparisonIndex=");
    line_append_dec(&line, comparison_index);
    line_append(&line, " number=");
    line_append_dec(&line, number);
    emit_line(&line);
    return;
  }
  static char decoded[MAX_LUA_OBJECT_NAME];
  uintptr_t entry = 0;
  uint32_t block = 0;
  uint32_t offset = 0;
  int is_wide = 0;
  const char *status = "unknown";
  int ok = decode_ue_fname(
    resolver,
    options,
    comparison_index,
    number,
    decoded,
    sizeof(decoded),
    &entry,
    &block,
    &offset,
    &is_wide,
    &status
  );
  static char safe_decoded[MAX_LUA_OBJECT_NAME];
  safe_value(decoded, safe_decoded, sizeof(safe_decoded));
  line_init(&line);
  line_append(&line, "event=ue-fname source=");
  line_append(&line, source);
  line_append(&line, " objectName=");
  line_append(&line, object_name);
  line_append(&line, " status=");
  line_append(&line, ok ? "decoded" : status);
  line_append(&line, " object=");
  line_append_hex(&line, object);
  line_append(&line, " pool=");
  line_append_hex(&line, resolver->pool);
  line_append(&line, " resolver=");
  line_append(&line, resolver->source);
  line_append(&line, " comparisonIndex=");
  line_append_dec(&line, comparison_index);
  line_append(&line, " number=");
  line_append_dec(&line, number);
  line_append(&line, " block=");
  line_append_dec(&line, block);
  line_append(&line, " offset=");
  line_append_hex(&line, offset);
  line_append(&line, " entry=");
  line_append_hex(&line, entry);
  line_append(&line, " wide=");
  line_append(&line, is_wide ? "true" : "false");
  line_append(&line, " decoded=");
  line_append(&line, ok ? safe_decoded : "");
  emit_line(&line);
  if (!ok) {
    log_ue_fname_decode_diagnostic(
      object_name,
      source,
      object,
      resolver,
      options,
      comparison_index,
      number,
      entry,
      status
    );
  }
}

static int register_lua_object_decoded_candidate(
  const char *source,
  const char *alias_of,
  const char *class_name,
  uintptr_t target,
  const char *decoded_name
) {
  if (!decoded_name || !decoded_name[0]) {
    return 0;
  }
  static char object_path[MAX_LUA_OBJECT_PATH];
  copy_string(object_path, sizeof(object_path), "/RuntimeProbe/");
  size_t prefix_len = cstr_len(object_path);
  size_t name_len = cstr_len(decoded_name);
  for (size_t i = 0; i < name_len && prefix_len + i + 1 < sizeof(object_path); ++i) {
    object_path[prefix_len + i] = decoded_name[i];
    object_path[prefix_len + i + 1] = '\0';
  }
  int registered_candidate = add_ue_candidate_object_handle(object_path, decoded_name, class_name, target);
  static Line line;
  line_init(&line);
  line_append(&line, "event=lua-object-registry source=");
  line_append(&line, source);
  line_append(&line, " status=");
  line_append(&line, registered_candidate ? "added" : "skipped");
  line_append(&line, " name=");
  line_append(&line, decoded_name);
  line_append(&line, " path=");
  line_append(&line, object_path);
  line_append(&line, " aliasOf=");
  line_append(&line, alias_of && alias_of[0] ? alias_of : "");
  line_append(&line, " class=");
  line_append(&line, class_name);
  line_append(&line, " address=");
  line_append_hex(&line, target);
  line_append(&line, " registryCount=");
  line_append_dec(&line, ue_candidate_object_handle_count);
  line_append(&line, " registryProvenance=");
  line_append(&line, registry_value_provenance(decoded_name, object_path, class_name));
  emit_line(&line);
  log_lua_object_registry_check(source, decoded_name, object_path, class_name, target);
  return registered_candidate;
}

__attribute__((noinline, used)) static int hook_self_test_target(int value) {
#if defined(__x86_64__) || defined(__amd64__) || defined(_M_X64)
  __asm__ __volatile__(
    ".rept 16\n"
    "nop\n"
    ".endr\n"
  );
#endif
  return value + 1;
}

__attribute__((noinline, used)) static int call_function_live_self_test_target(
  void *object,
  const void *command,
  void *output,
  void *executor,
  int force_call
) {
#if defined(__x86_64__) || defined(__amd64__) || defined(_M_X64)
  __asm__ __volatile__(
    ".rept 16\n"
    "nop\n"
    ".endr\n"
  );
#endif
  (void)output;
  (void)executor;
  return object && command ? 40 + (force_call ? 2 : 1) : 0;
}

static void reset_hook_dispatch_slots(void) {
  unsigned char *bytes = (unsigned char *)hook_dispatch_slots;
  for (size_t i = 0; i < sizeof(hook_dispatch_slots); ++i) {
    bytes[i] = 0;
  }
  hook_dispatch_slot_count = 0;
  hook_self_test_last_original = 0;
  hook_self_test_last_pre_callbacks = 0;
  hook_self_test_last_post_callbacks = 0;
}

static int register_hook_dispatch_callback(HookDispatchStage stage, HookDispatchCallback callback, void *user) {
  if (!callback || hook_dispatch_slot_count >= MAX_HOOK_DISPATCH_CALLBACKS) {
    return 0;
  }
  hook_dispatch_slots[hook_dispatch_slot_count].stage = stage;
  hook_dispatch_slots[hook_dispatch_slot_count].callback = callback;
  hook_dispatch_slots[hook_dispatch_slot_count].user = user;
  ++hook_dispatch_slot_count;
  return 1;
}

static void hook_self_test_pre_callback(HookDispatchContext *ctx, void *user) {
  (void)user;
  ++ctx->pre_callbacks;
}

static void hook_self_test_post_callback(HookDispatchContext *ctx, void *user) {
  (void)user;
  ++ctx->post_callbacks;
}

static void reset_mod_dispatch_entries(void) {
  unsigned char *bytes = (unsigned char *)mod_dispatch_entries;
  for (size_t i = 0; i < sizeof(mod_dispatch_entries); ++i) {
    bytes[i] = 0;
  }
  mod_dispatch_entry_count = 0;
  mod_self_test_load_callbacks = 0;
  mod_self_test_unload_callbacks = 0;
}

static int register_mod_dispatch_entry(const ModDispatchEntry *entry) {
  if (!entry || !entry->name || mod_dispatch_entry_count >= MAX_MOD_DISPATCH_ENTRIES) {
    return 0;
  }
  mod_dispatch_entries[mod_dispatch_entry_count++] = *entry;
  return 1;
}

static int load_mod_dispatch_entries(void) {
  int loaded = 0;
  for (size_t i = 0; i < mod_dispatch_entry_count; ++i) {
    ModDispatchEntry *entry = &mod_dispatch_entries[i];
    if (entry->on_load) {
      entry->on_load(entry->user);
    }
    if (entry->on_pre_hook && !register_hook_dispatch_callback(HOOK_DISPATCH_PRE, entry->on_pre_hook, entry->user)) {
      continue;
    }
    if (entry->on_post_hook && !register_hook_dispatch_callback(HOOK_DISPATCH_POST, entry->on_post_hook, entry->user)) {
      continue;
    }
    entry->loaded = 1;
    ++loaded;
  }
  return loaded;
}

static int unload_mod_dispatch_entries(void) {
  int unloaded = 0;
  for (size_t i = 0; i < mod_dispatch_entry_count; ++i) {
    ModDispatchEntry *entry = &mod_dispatch_entries[i];
    if (!entry->loaded) {
      continue;
    }
    if (entry->on_unload) {
      entry->on_unload(entry->user);
    }
    entry->loaded = 0;
    ++unloaded;
  }
  return unloaded;
}

static void mod_self_test_load(void *user) {
  (void)user;
  ++mod_self_test_load_callbacks;
}

static void mod_self_test_unload(void *user) {
  (void)user;
  ++mod_self_test_unload_callbacks;
}

static void run_dispatch_callbacks(HookDispatchStage stage, HookDispatchContext *ctx) {
  for (size_t i = 0; i < hook_dispatch_slot_count; ++i) {
    if (hook_dispatch_slots[i].stage == stage && hook_dispatch_slots[i].callback) {
      hook_dispatch_slots[i].callback(ctx, hook_dispatch_slots[i].user);
    }
  }
}

static void reset_process_event_dispatch_slots(void) {
  unsigned char *bytes = (unsigned char *)process_event_dispatch_slots;
  for (size_t i = 0; i < sizeof(process_event_dispatch_slots); ++i) {
    bytes[i] = 0;
  }
  process_event_dispatch_slot_count = 0;
  process_event_live_hook_last_pre_callbacks = 0;
  process_event_live_hook_last_post_callbacks = 0;
}

static int register_process_event_dispatch_callback(HookDispatchStage stage, ProcessEventDispatchCallback callback, void *user) {
  if (!callback || process_event_dispatch_slot_count >= MAX_HOOK_DISPATCH_CALLBACKS) {
    return 0;
  }
  process_event_dispatch_slots[process_event_dispatch_slot_count].stage = stage;
  process_event_dispatch_slots[process_event_dispatch_slot_count].callback = callback;
  process_event_dispatch_slots[process_event_dispatch_slot_count].user = user;
  ++process_event_dispatch_slot_count;
  return 1;
}

static void process_event_dispatch_self_test_pre(ProcessEventDispatchContext *ctx, void *user) {
  (void)user;
  ++ctx->pre_callbacks;
}

static void process_event_dispatch_self_test_post(ProcessEventDispatchContext *ctx, void *user) {
  (void)user;
  ++ctx->post_callbacks;
}

static void run_process_event_dispatch_callbacks(HookDispatchStage stage, ProcessEventDispatchContext *ctx) {
  for (size_t i = 0; i < process_event_dispatch_slot_count; ++i) {
    if (process_event_dispatch_slots[i].stage == stage && process_event_dispatch_slots[i].callback) {
      process_event_dispatch_slots[i].callback(ctx, process_event_dispatch_slots[i].user);
    }
  }
}

static int dispatch_hook_self_test(int value) {
  HookDispatchContext ctx;
  unsigned char *bytes = (unsigned char *)&ctx;
  for (size_t i = 0; i < sizeof(ctx); ++i) {
    bytes[i] = 0;
  }
  ctx.value = value;
  run_dispatch_callbacks(HOOK_DISPATCH_PRE, &ctx);

  HookSelfTestFn original = hook_self_test_original;
  ctx.original_result = original ? original(ctx.value) : ctx.value + 1;
  ctx.result = ctx.original_result + 1000;

  run_dispatch_callbacks(HOOK_DISPATCH_POST, &ctx);
  hook_self_test_last_original = ctx.original_result;
  hook_self_test_last_pre_callbacks = ctx.pre_callbacks;
  hook_self_test_last_post_callbacks = ctx.post_callbacks;
  return ctx.result;
}

static void run_mod_dispatch_self_test(const char *phase) {
  if (!env_bool("DUNE_WIN_CLIENT_PROBE_MOD_SELF_TEST", 0)) {
    return;
  }
  reset_hook_dispatch_slots();
  reset_mod_dispatch_entries();
  ModDispatchEntry entry = {
    "SelfTestMod",
    mod_self_test_load,
    hook_self_test_pre_callback,
    hook_self_test_post_callback,
    mod_self_test_unload,
    0,
    0,
  };
  int registered = register_mod_dispatch_entry(&entry);
  int loaded = load_mod_dispatch_entries();
  hook_self_test_original = hook_self_test_target;
  int result = dispatch_hook_self_test(41);
  hook_self_test_original = 0;
  int unloaded = unload_mod_dispatch_entries();
  const char *status = registered && loaded == 1 && result == 1042 &&
                       hook_self_test_last_original == 42 &&
                       hook_self_test_last_pre_callbacks == 1 &&
                       hook_self_test_last_post_callbacks == 1 &&
                       mod_self_test_load_callbacks == 1 &&
                       mod_self_test_unload_callbacks == 1 &&
                       unloaded == 1 ? "passed" : "failed";

  static Line line;
  line_init(&line);
  line_append(&line, "event=mod-dispatch-self-test phase=");
  line_append(&line, phase);
  line_append(&line, " status=");
  line_append(&line, status);
  line_append(&line, " mods=");
  line_append_dec(&line, mod_dispatch_entry_count);
  line_append(&line, " loaded=");
  line_append_signed_dec(&line, loaded);
  line_append(&line, " unloaded=");
  line_append_signed_dec(&line, unloaded);
  line_append(&line, " result=");
  line_append_signed_dec(&line, result);
  line_append(&line, " original=");
  line_append_signed_dec(&line, hook_self_test_last_original);
  line_append(&line, " callbacks=");
  line_append_dec(&line, hook_dispatch_slot_count);
  line_append(&line, " preCallbacks=");
  line_append_signed_dec(&line, hook_self_test_last_pre_callbacks);
  line_append(&line, " postCallbacks=");
  line_append_signed_dec(&line, hook_self_test_last_post_callbacks);
  line_append(&line, " loadCallbacks=");
  line_append_signed_dec(&line, mod_self_test_load_callbacks);
  line_append(&line, " unloadCallbacks=");
  line_append_signed_dec(&line, mod_self_test_unload_callbacks);
  emit_line(&line);
}

#define LOAD_LUA_SYMBOL(api, field, type, symbol_name) \
  do { \
    union { void *ptr; type fn; } lua_symbol; \
    lua_symbol.ptr = GetProcAddress((api)->module, (symbol_name)); \
    (api)->field = lua_symbol.fn; \
  } while (0)

static void zero_lua_api(LuaApi *api) {
  unsigned char *bytes = (unsigned char *)api;
  for (size_t i = 0; i < sizeof(*api); ++i) {
    bytes[i] = 0;
  }
}

static int load_lua_api_from_library(const char *library, LuaApi *api) {
  if (!library || !library[0] || !api) {
    return 0;
  }
  HMODULE module = LoadLibraryA(library);
  if (!module) {
    return 0;
  }
  zero_lua_api(api);
  api->module = module;
  copy_string(api->library, sizeof(api->library), library);
  LOAD_LUA_SYMBOL(api, new_state, LuaNewStateFn, "luaL_newstate");
  LOAD_LUA_SYMBOL(api, open_libs, LuaOpenLibsFn, "luaL_openlibs");
  LOAD_LUA_SYMBOL(api, load_string, LuaLoadStringFn, "luaL_loadstring");
  LOAD_LUA_SYMBOL(api, pcallk, LuaPCallKFn, "lua_pcallk");
  LOAD_LUA_SYMBOL(api, pcall, LuaPCallFn, "lua_pcall");
  LOAD_LUA_SYMBOL(api, to_integerx, LuaToIntegerXFn, "lua_tointegerx");
  LOAD_LUA_SYMBOL(api, to_integer, LuaToIntegerFn, "lua_tointeger");
  LOAD_LUA_SYMBOL(api, to_numberx, LuaToNumberXFn, "lua_tonumberx");
  LOAD_LUA_SYMBOL(api, to_number, LuaToNumberFn, "lua_tonumber");
  LOAD_LUA_SYMBOL(api, to_lstring, LuaToLStringFn, "lua_tolstring");
  LOAD_LUA_SYMBOL(api, to_boolean, LuaToBooleanFn, "lua_toboolean");
  LOAD_LUA_SYMBOL(api, push_cclosure, LuaPushCClosureFn, "lua_pushcclosure");
  LOAD_LUA_SYMBOL(api, set_global, LuaSetGlobalFn, "lua_setglobal");
  LOAD_LUA_SYMBOL(api, push_integer, LuaPushIntegerFn, "lua_pushinteger");
  LOAD_LUA_SYMBOL(api, push_number, LuaPushNumberFn, "lua_pushnumber");
  LOAD_LUA_SYMBOL(api, push_nil, LuaPushNilFn, "lua_pushnil");
  LOAD_LUA_SYMBOL(api, push_string, LuaPushStringFn, "lua_pushstring");
  LOAD_LUA_SYMBOL(api, push_boolean, LuaPushBooleanFn, "lua_pushboolean");
  LOAD_LUA_SYMBOL(api, create_table, LuaCreateTableFn, "lua_createtable");
  LOAD_LUA_SYMBOL(api, set_field, LuaSetFieldFn, "lua_setfield");
  LOAD_LUA_SYMBOL(api, type, LuaTypeFn, "lua_type");
  LOAD_LUA_SYMBOL(api, push_value, LuaPushValueFn, "lua_pushvalue");
  LOAD_LUA_SYMBOL(api, ref, LuaLRefFn, "luaL_ref");
  LOAD_LUA_SYMBOL(api, rawgeti, LuaRawGetIFn, "lua_rawgeti");
  LOAD_LUA_SYMBOL(api, rawseti, LuaRawSetIFn, "lua_rawseti");
  LOAD_LUA_SYMBOL(api, unref, LuaLUnrefFn, "luaL_unref");
  LOAD_LUA_SYMBOL(api, set_top, LuaSetTopFn, "lua_settop");
  LOAD_LUA_SYMBOL(api, get_field, LuaGetFieldFn, "lua_getfield");
  LOAD_LUA_SYMBOL(api, close, LuaCloseFn, "lua_close");
  if (!api->new_state || !api->open_libs || !api->load_string || (!api->pcallk && !api->pcall) ||
      (!api->to_integerx && !api->to_integer) || (!api->to_numberx && !api->to_number) ||
      !api->to_lstring ||
      !api->push_cclosure || !api->set_global || !api->push_integer || !api->push_number || !api->push_nil ||
      !api->to_boolean || !api->push_string || !api->push_boolean || !api->create_table || !api->set_field ||
      !api->type || !api->push_value || !api->ref || !api->rawgeti || !api->rawseti || !api->set_top ||
      !api->get_field ||
      !api->close) {
    FreeLibrary(module);
    zero_lua_api(api);
    return 0;
  }
  return 1;
}

static int load_lua_api(LuaApi *api) {
  static char configured[512];
  if (env_get("DUNE_WIN_CLIENT_PROBE_LUA_DLL", configured, sizeof(configured)) > 0 &&
      configured[0] && load_lua_api_from_library(configured, api)) {
    return 1;
  }
  static const char *candidates[] = {
    "lua54.dll",
    "lua5.4.dll",
    "lua.dll",
    "luajit.dll",
  };
  for (size_t i = 0; i < sizeof(candidates) / sizeof(candidates[0]); ++i) {
    if (load_lua_api_from_library(candidates[i], api)) {
      return 1;
    }
  }
  return 0;
}

static int lua_call(LuaApi *api, LuaState *state, int nargs, int nresults, int errfunc) {
  if (api->pcallk) {
    return api->pcallk(state, nargs, nresults, errfunc, 0, 0);
  }
  return api->pcall(state, nargs, nresults, errfunc);
}

static long long lua_to_integer(LuaApi *api, LuaState *state, int index, int *is_number) {
  if (api->to_integerx) {
    return api->to_integerx(state, index, is_number);
  }
  if (is_number) {
    *is_number = 1;
  }
  return api->to_integer(state, index);
}

static double lua_to_number(LuaApi *api, LuaState *state, int index, int *is_number) {
  if (is_number) {
    *is_number = 0;
  }
  if (!api || !state) {
    return 0.0;
  }
  if (api->to_numberx) {
    return api->to_numberx(state, index, is_number);
  }
  if (api->type && api->type(state, index) != LUA_TNUMBER_COMPAT) {
    return 0.0;
  }
  if (is_number) {
    *is_number = 1;
  }
  return api->to_number ? api->to_number(state, index) : 0.0;
}

static int lua_to_boolean(LuaApi *api, LuaState *state, int index, int *is_boolean) {
  if (is_boolean) {
    *is_boolean = 0;
  }
  if (!api || !state) {
    return 0;
  }
  if (api->type && api->type(state, index) == LUA_TBOOLEAN_COMPAT && api->to_boolean) {
    if (is_boolean) {
      *is_boolean = 1;
    }
    return api->to_boolean(state, index) != 0;
  }
  int is_number = 0;
  long long value = lua_to_integer(api, state, index, &is_number);
  if (is_number) {
    if (is_boolean) {
      *is_boolean = 1;
    }
    return value != 0;
  }
  return 0;
}

static const char *path_basename_win(const char *path);

static int add_object_handle_to(
  LuaObjectHandle *handles,
  size_t *count,
  const char *path,
  const char *name,
  const char *class_name,
  uintptr_t address
) {
  if (!handles || !count || !path || !path[0] || *count >= MAX_LUA_OBJECT_HANDLES) {
    return 0;
  }
  LuaObjectHandle *object = &handles[(*count)++];
  copy_string(object->path, sizeof(object->path), path);
  copy_string(object->name, sizeof(object->name), (name && name[0]) ? name : path_basename_win(path));
  copy_string(object->class_name, sizeof(object->class_name), (class_name && class_name[0]) ? class_name : "UObject");
  object->address = address;
  object->class_address = 0;
  object->outer_address = 0;
  object->super_address = 0;
  object->object_flags = 0;
  object->internal_index = 0;
  object->has_object_metadata = 0;
  object->internal_flags = 0;
  object->has_internal_flags = 0;
  object->function_flags = 0;
  object->has_function_flags = 0;
  return 1;
}

static int add_lua_object_handle(const char *path, const char *name, const char *class_name, uintptr_t address) {
  return add_object_handle_to(&lua_object_handles[0], &lua_object_handle_count, path, name, class_name, address);
}

static int add_ue_candidate_object_handle(const char *path, const char *name, const char *class_name, uintptr_t address) {
  const char *candidate_name = (name && name[0]) ? name : path_basename_win(path);
  for (size_t i = 0; i < ue_candidate_object_handle_count; ++i) {
    const LuaObjectHandle *object = &ue_candidate_object_handles[i];
    if (object->address == address &&
        (str_equal(object->path, path) || str_equal(object->name, candidate_name))) {
      return 0;
    }
  }
  return add_object_handle_to(&ue_candidate_object_handles[0], &ue_candidate_object_handle_count, path, name, class_name, address);
}

static void update_ue_candidate_object_metadata(uintptr_t address, uintptr_t class_address, uintptr_t outer_address, uintptr_t super_address) {
  if (!address) {
    return;
  }
  for (size_t i = 0; i < ue_candidate_object_handle_count; ++i) {
    LuaObjectHandle *object = &ue_candidate_object_handles[i];
    if (object->address != address) {
      continue;
    }
    if (class_address) {
      object->class_address = class_address;
    }
    if (outer_address) {
      object->outer_address = outer_address;
    }
    if (super_address) {
      object->super_address = super_address;
    }
  }
}

static void update_ue_candidate_object_layout_metadata(uintptr_t address, uint32_t object_flags, int32_t internal_index) {
  if (!address) {
    return;
  }
  for (size_t i = 0; i < ue_candidate_object_handle_count; ++i) {
    LuaObjectHandle *object = &ue_candidate_object_handles[i];
    if (object->address != address) {
      continue;
    }
    object->object_flags = object_flags;
    object->internal_index = internal_index;
    object->has_object_metadata = 1;
  }
}

static void update_ue_candidate_object_internal_flags(uintptr_t address, uint32_t internal_flags, int has_internal_flags) {
  if (!address || !has_internal_flags) {
    return;
  }
  for (size_t i = 0; i < ue_candidate_object_handle_count; ++i) {
    LuaObjectHandle *object = &ue_candidate_object_handles[i];
    if (object->address != address) {
      continue;
    }
    object->internal_flags = internal_flags;
    object->has_internal_flags = 1;
  }
}

static const LuaClassMetadata *find_lua_class_metadata_by_address(uintptr_t address) {
  if (!address) {
    return 0;
  }
  for (size_t i = 0; i < lua_class_metadata_count; ++i) {
    if (lua_class_metadata[i].address == address) {
      return &lua_class_metadata[i];
    }
  }
  return 0;
}

static void record_lua_class_metadata(uintptr_t address, uintptr_t super_address, const char *name) {
  if (!address) {
    return;
  }
  for (size_t i = 0; i < lua_class_metadata_count; ++i) {
    LuaClassMetadata *metadata = &lua_class_metadata[i];
    if (metadata->address != address) {
      continue;
    }
    if (super_address) {
      metadata->super_address = super_address;
    }
    if (name && name[0]) {
      copy_string(metadata->name, sizeof(metadata->name), name);
    }
    return;
  }
  if (lua_class_metadata_count >= MAX_LUA_CLASS_METADATA) {
    return;
  }
  LuaClassMetadata *metadata = &lua_class_metadata[lua_class_metadata_count++];
  for (size_t i = 0; i < sizeof(*metadata); ++i) {
    ((unsigned char *)metadata)[i] = 0;
  }
  metadata->address = address;
  metadata->super_address = super_address;
  if (name && name[0]) {
    copy_string(metadata->name, sizeof(metadata->name), name);
  }
}

