static int load_asset_package_return_validation_ready(
  const char *self_test_path,
  uintptr_t candidate_address,
  const char *expected_class,
  uintptr_t *address_out,
  const char **path_out,
  int *registry_hit_out,
  int *mapped_out,
  int *readable_out,
  int *class_match_out
) {
  const LuaObjectHandle *object = candidate_address ?
    find_lua_object_by_address(candidate_address) :
    find_lua_object_by_path_or_name(self_test_path);
  int registry_hit = object && object->address &&
                     find_lua_object_by_address(object->address) == object &&
                     (!candidate_address || object->address == candidate_address);
  int class_match = object && (!expected_class || !expected_class[0] || str_equal(object->class_name, expected_class));
  int mapped = 0;
  int readable = 0;
  uintptr_t address = object ? object->address : candidate_address;
  MEMORY_BASIC_INFORMATION_WIN64 mbi;
  SIZE_T got = address ? VirtualQuery((const void *)address, &mbi, sizeof(mbi)) : 0;
  if (got && mbi.State == MEM_COMMIT) {
    mapped = 1;
    readable = readable_protect(mbi.Protect) && region_contains_range(&mbi, address, sizeof(UeSelfTestObject));
  }

  if (address_out) *address_out = address;
  if (path_out) *path_out = object ? object->path : (self_test_path ? self_test_path : "");
  if (registry_hit_out) *registry_hit_out = registry_hit;
  if (mapped_out) *mapped_out = mapped;
  if (readable_out) *readable_out = readable;
  if (class_match_out) *class_match_out = class_match;
  return registry_hit && mapped && readable && class_match;
}

static int load_asset_package_native_return_memory_ready(
  uintptr_t address,
  int *non_null_out,
  int *mapped_out,
  int *readable_out
) {
  int non_null = address != 0;
  int mapped = 0;
  int readable = 0;
  if (non_null) {
    MEMORY_BASIC_INFORMATION_WIN64 mbi;
    zero_bytes(&mbi, sizeof(mbi));
    SIZE_T got = VirtualQuery((const void *)address, &mbi, sizeof(mbi));
    if (got && mbi.State == MEM_COMMIT) {
      mapped = 1;
      readable = readable_protect(mbi.Protect) && region_contains_range(&mbi, address, sizeof(void *));
    }
  }
  if (non_null_out) *non_null_out = non_null;
  if (mapped_out) *mapped_out = mapped;
  if (readable_out) *readable_out = readable;
  return non_null && mapped && readable;
}

