      export_format_fixed3(component, sizeof(component), x);
      export_append_string_to_buffer(value, sizeof(value), &value_len, component);
      export_append_string_to_buffer(value, sizeof(value), &value_len, ",Y=");
      export_format_fixed3(component, sizeof(component), y);
      export_append_string_to_buffer(value, sizeof(value), &value_len, component);
      export_append_string_to_buffer(value, sizeof(value), &value_len, ",Z=");
